do
-- Menu
local tracer = ui.new_checkbox("VISUALS", "Effects", "Bullet tracers redux")
local color = ui.new_color_picker("VISUALS", "Effects", "Color", 255, 255, 255, 255)

-- Variables and constants
local queue = {}

-- Game event handling
client.set_event_callback("bullet_impact", function(e)
    if not ui.get(tracer) then
        return
    end
    if client.userid_to_entindex(e.userid) ~= entity.get_local_player() then
        return
    end
    local lx, ly, lz = client.eye_position()
    queue[globals.tickcount()] = {lx, ly, lz, e.x, e.y, e.z, globals.curtime() + 2}
end)

client.set_event_callback("paint", function()
    if not ui.get(tracer) then
        return
    end
    for tick, data in pairs(queue) do
        if globals.curtime() <= data[7] then
            local x1, y1 = renderer.world_to_screen(data[1], data[2], data[3])
            local x2, y2 = renderer.world_to_screen(data[4], data[5], data[6])
            if x1 ~= nil and x2 ~= nil and y1 ~= nil and y2 ~= nil then
                renderer.line(x1, y1, x2, y2, ui.get(color))
            end
        end
    end
end)

client.set_event_callback("round_prestart", function()
    if not ui.get(tracer) then
        return
    end
    queue = {}
end)
end
-- ============================================================================
-- Cryonova custom health bar
-- ============================================================================

local cryonova_health_bar do
    local hpbar = {
        customhealthbars = ui.new_checkbox('VISUALS', 'Player ESP', 'Cryonova health bar'),
        gradient = ui.new_checkbox('VISUALS', 'Player ESP', 'Enable health gradient'),
        label = ui.new_label('VISUALS', 'Player ESP', 'Full Health'),
        colorpicker = ui.new_color_picker('VISUALS', 'Player ESP', 'Full Health', 142, 214, 77, 255),
        label2 = ui.new_label('VISUALS', 'Player ESP', 'Empty Health'),
        colorpicker2 = ui.new_color_picker('VISUALS', 'Player ESP', 'Empty Health', 244, 48, 87, 255)
    }

    local players = { }
    local standard_health_bar = ui.reference('VISUALS', 'Player ESP', 'Health bar')
    local teammates_ref = ui.reference('VISUALS', 'Player ESP', 'Teammates')

    local function lerp(a, b, percentage)
        return a + (b - a) * percentage
    end

    local function clamp(value, min_value, max_value)
        if value < min_value then
            return min_value
        end

        if value > max_value then
            return max_value
        end

        return value
    end

    local function set_menu_visible(enabled)
        ui.set_visible(hpbar.gradient, enabled)
        ui.set_visible(hpbar.label, enabled)
        ui.set_visible(hpbar.label2, enabled)
        ui.set_visible(hpbar.colorpicker, enabled)
        ui.set_visible(hpbar.colorpicker2, enabled)
    end

    local function handle_checkbox()
        local enabled = ui.get(hpbar.customhealthbars)

        if enabled then
            ui.set(standard_health_bar, false)
        end

        set_menu_visible(enabled)
    end

    local function draw_bar(ent, health, percentage, alpha)
        local x1, y1, x2, y2 = entity.get_bounding_box(ent)

        if x1 == nil or y1 == nil or x2 == nil or y2 == nil then
            return false
        end

        local r, g, b = ui.get(hpbar.colorpicker)
        local r2, g2, b2 = ui.get(hpbar.colorpicker2)
        local height = y2 - y1 + 2
        local leftside = x1 - 5
        local fill_height = math.floor(height * percentage) - 2
        local fill_y = math.ceil(y2 - (height * percentage)) + 2
        local new_r = lerp(r2, r, percentage)
        local new_g = lerp(g2, g, percentage)
        local new_b = lerp(b2, b, percentage)

        y1 = y1 - 1
        alpha = clamp(alpha or 255, 0, 255)

        renderer.rectangle(leftside - 1, y1, 4, height, 20, 20, 20, 150 * (alpha / 255))

        if fill_height > 0 then
            if ui.get(hpbar.gradient) then
                renderer.gradient(leftside, fill_y, 2, fill_height, new_r, new_g, new_b, alpha, r2, g2, b2, alpha, false)
            else
                renderer.rectangle(leftside, fill_y, 2, fill_height, new_r, new_g, new_b, alpha)
            end
        end

        if health < 100 then
            renderer.text(leftside - 2, y2 - (height * percentage) + 2, 255, 255, 255, alpha, '-cd', 0, health)
        end

        return true
    end

    local function should_draw_player(local_player, ent, force_teammates)
        if entity.is_dormant(ent) then
            return false
        end

        if entity.is_alive(local_player) then
            return true
        end

        return not force_teammates or force_teammates and not entity.is_enemy(ent)
    end

    local function on_round_end()
        players = { }
    end

    local function on_paint()
        if not ui.get(hpbar.customhealthbars) then
            return
        end

        local local_player = entity.get_local_player()

        if local_player == nil then
            return
        end

        local force_teammates = ui.get(teammates_ref)

        if not entity.is_alive(local_player) then
            local observer_mode = entity.get_prop(local_player, 'm_iObserverMode')

            if observer_mode == 4 or observer_mode == 5 then
                local spectated_ent = entity.get_prop(local_player, 'm_hObserverTarget')

                if spectated_ent ~= nil and entity.is_enemy(spectated_ent) then
                    force_teammates = true
                end
            end
        end

        local enemy_players = entity.get_players(not force_teammates)

        for _, data in pairs(players) do
            data.active = false
        end

        for i = 1, #enemy_players do
            local ent = enemy_players[i]

            if should_draw_player(local_player, ent, force_teammates) then
                local hp = entity.get_prop(ent, 'm_iHealth')

                if hp ~= nil then
                    hp = clamp(hp, 0, 100)

                    local percentage = clamp(hp / 100, 0, 1)
                    local name = entity.get_player_name(ent)

                    if draw_bar(ent, hp, percentage, 255) then
                        players[name] = {
                            ent = ent,
                            health = hp,
                            health_percentage = percentage,
                            active = true,
                            alpha = 255
                        }
                    end
                end
            end
        end

        if entity.is_alive(local_player) then
            for key, data in pairs(players) do
                if not data.active and entity.is_alive(data.ent) then
                    draw_bar(data.ent, data.health, data.health_percentage, data.alpha)
                    data.alpha = data.alpha - 0.25
                end

                if data.alpha < 0 then
                    players[key] = nil
                end
            end
        end
    end

    set_menu_visible(false)
    ui.set_callback(hpbar.customhealthbars, handle_checkbox)
    client.set_event_callback('round_end', on_round_end)
    client.set_event_callback('paint', on_paint)
end
-- ============================================================================
-- Codex visual extras
-- ============================================================================

local codex_visuals do
    local ref = {
        enabled = ui.new_checkbox("VISUALS", "Effects", "Codex visual extras"),
        color = ui.new_color_picker("VISUALS", "Effects", "Codex visual extras color", 120, 190, 255, 210),
        tracers = ui.new_checkbox("VISUALS", "Effects", "Extra impact glow"),
        dormant = ui.new_checkbox("VISUALS", "Player ESP", "Dormant pulse marker")
    }

    ui.set(ref.tracers, true)
    ui.set(ref.dormant, true)

    local impacts = {}

    local function clamp(value, min_value, max_value)
        if value < min_value then
            return min_value
        end

        if value > max_value then
            return max_value
        end

        return value
    end

    local function lerp(a, b, t)
        return a + (b - a) * t
    end

    local function on_bullet_impact(e)
        if not ui.get(ref.enabled) or not ui.get(ref.tracers) then
            return
        end

        if client.userid_to_entindex(e.userid) ~= entity.get_local_player() then
            return
        end

        local sx, sy, sz = client.eye_position()
        if sx == nil then
            return
        end

        impacts[#impacts + 1] = {
            sx = sx,
            sy = sy,
            sz = sz,
            ex = e.x,
            ey = e.y,
            ez = e.z,
            time = globals.realtime(),
            death = globals.realtime() + 1.15
        }

        if #impacts > 42 then
            table.remove(impacts, 1)
        end
    end

    local function draw_impacts()
        local now = globals.realtime()
        local r, g, b, a = ui.get(ref.color)

        for i = #impacts, 1, -1 do
            local impact = impacts[i]
            local life = (impact.death - now) / (impact.death - impact.time)

            if life <= 0 then
                table.remove(impacts, i)
            else
                local x1, y1 = renderer.world_to_screen(impact.sx, impact.sy, impact.sz)
                local x2, y2 = renderer.world_to_screen(impact.ex, impact.ey, impact.ez)

                if x1 ~= nil and x2 ~= nil then
                    local alpha = clamp(a * life, 0, 255)
                    local width = lerp(1, 4, life)

                    renderer.line(x1 - 1, y1, x2 - 1, y2, r, g, b, alpha * 0.25)
                    renderer.line(x1 + 1, y1, x2 + 1, y2, r, g, b, alpha * 0.25)
                    renderer.line(x1, y1, x2, y2, r, g, b, alpha)
                    renderer.circle(x2, y2, r, g, b, alpha, width, 0, 1)
                end
            end
        end
    end

    local function draw_dormant_pulse()
        local me = entity.get_local_player()
        if me == nil or not entity.is_alive(me) then
            return
        end

        local r, g, b, a = ui.get(ref.color)
        local pulse = (math.sin(globals.realtime() * 5) + 1) * 0.5

        for i = 1, globals.maxplayers() do
            if i ~= me and entity.is_enemy(i) and entity.is_alive(i) and entity.is_dormant(i) then
                local ox, oy, oz = entity.get_origin(i)

                if ox ~= nil then
                    local x, y = renderer.world_to_screen(ox, oy, oz + 74)

                    if x ~= nil then
                        local alpha = clamp(a * (0.35 + pulse * 0.45), 0, 255)
                        local radius = 5 + pulse * 5
                        local name = entity.get_player_name(i) or "dormant"

                        renderer.circle_outline(x, y, r, g, b, alpha, radius, 0, 1, 2)
                        renderer.text(x, y - 18, r, g, b, alpha, "cb", 0, "DORMANT")
                        renderer.text(x, y - 7, 255, 255, 255, alpha * 0.85, "cb", 0, name)
                    end
                end
            end
        end
    end

    local function on_paint()
        if not ui.get(ref.enabled) then
            return
        end

        if ui.get(ref.tracers) then
            draw_impacts()
        end

        if ui.get(ref.dormant) then
            draw_dormant_pulse()
        end
    end

    local function on_round_prestart()
        impacts = {}
    end

    client.set_event_callback("bullet_impact", on_bullet_impact)
    client.set_event_callback("paint", on_paint)
    client.set_event_callback("round_prestart", on_round_prestart)
end

local c_entity = require 'gamesense/entity'
local csgo_weapons = require 'gamesense/csgo_weapons'

local function DUMMY(...)
    return ...
end

local function contains(list, value)
    for i = 1, #list do
        if list[i] == value then
            return i
        end
    end

    return nil
end

local function round(x)
    return math.floor(x + 0.5)
end

local script do
    script = { }

    local function get_steam_username()
        local ok, result = pcall(function()
            local panorama_api = panorama.open()
            local my_persona_api = panorama_api and panorama_api.MyPersonaAPI

            if my_persona_api == nil or my_persona_api.GetName == nil then
                return nil
            end

            return my_persona_api.GetName()
        end)

        if ok and result ~= nil and result ~= '' then
            return result
        end

        return _USER_NAME or 'h3xc0l0r'
    end

    script.name = 'Revision'
    script.build = 'Nightly'

    script.user = get_steam_username()
end

