    local cdn_urls = {
        mark = {
            'https://raw.githubusercontent.com/s4456068-hub/Cryonova/main/cryonova_mark.png'
        },
        intro_logo = {
            'https://raw.githubusercontent.com/s4456068-hub/Cryonova/main/cryonova_intro_logo.png'
        }
    }

    local local_png_paths = {
        mark = 'Visuals\\cryonova_mark.png',
        intro_logo = 'Visuals\\cryonova_intro_logo.png'
    }

    local panorama_png_paths = {
        mark = {
            'csgo\\materials\\panorama\\images\\icons\\cryonova\\cryonova_mark_64.png',
            'materials\\panorama\\images\\icons\\cryonova\\cryonova_mark_64.png'
        }
    }

    local CreateDir = nil do
        local ok, result = pcall(function()
            return vtable_bind('filesystem_stdio.dll', 'VFileSystem017', 22, ffi.typeof [[
                void(__thiscall*)(void*, const char *pPath, const char *pathID)
            ]])
        end)

        if ok then
            CreateDir = result
        end
    end

    local function create_parent_dirs(path)
        if CreateDir == nil or type(path) ~= 'string' then
            return
        end

        local current = ''

        for part in path:gmatch('[^\\]+') do
            if part:find('%.') then
                break
            end

            current = current == '' and part or (current .. '\\' .. part)
            pcall(CreateDir, current, 'GAME')
        end
    end

    local function load_png_bytes(bytes)
        if bytes == nil then
            return false
        end

        local loaded, image = pcall(images.load_png, bytes)

        if loaded and image ~= nil then
            return image
        end

        return false
    end

    local function get_embedded_png_bytes(key)
        local data = embedded_pngs[key]

        if data == nil then
            return nil
        end

        local ok, bytes = pcall(base64.decode, data:gsub('%s', ''))

        if not ok or bytes == nil then
            return nil
        end

        return bytes
    end

    local function load_embedded_png(key)
        return load_png_bytes(get_embedded_png_bytes(key))
    end

    local function load_png(paths)
        for i = 1, #paths do
            local ok, bytes = pcall(readfile, paths[i])

            if ok and bytes ~= nil then
                local image = load_png_bytes(bytes)

                if image ~= false then
                    return image
                end
            end
        end

        return false
    end

    local function load_png_from_url(key, urls)
        if http == nil or cryonova_assets[key] ~= nil or cryonova_assets[key .. '_loading'] then
            return
        end

        cryonova_assets[key .. '_loading'] = true

        local index = 1

        local function request_next()
            local url = urls[index]

            if url == nil then
                cryonova_assets[key] = false
                cryonova_assets[key .. '_loading'] = false
                return
            end

            http.get(url, function(success, response)
                if success and response ~= nil and response.status == 200 and response.body ~= nil then
                    local image = load_png_bytes(response.body)

                    if image ~= false then
                        if local_png_paths[key] ~= nil and writefile ~= nil then
                            pcall(writefile, local_png_paths[key], response.body)
                        end

                        if panorama_png_paths[key] ~= nil and writefile ~= nil then
                            for i = 1, #panorama_png_paths[key] do
                                create_parent_dirs(panorama_png_paths[key][i])
                                pcall(writefile, panorama_png_paths[key][i], response.body)
                            end
                        end

                        cryonova_assets[key] = image
                        cryonova_assets[key .. '_loading'] = false
                        return
                    end
                end

                index = index + 1
                request_next()
            end)
        end

        request_next()
    end

    local function read_valid_png_bytes(paths)
        if type(paths) ~= 'table' then
            return nil
        end

        for i = 1, #paths do
            local ok, bytes = pcall(readfile, paths[i])

            if ok and bytes ~= nil and load_png_bytes(bytes) ~= false then
                return bytes
            end
        end

        return nil
    end

    function cryonova_assets.ensure_panorama_mark()
        local paths = panorama_png_paths.mark

        if paths == nil or writefile == nil then
            return false
        end

        if read_valid_png_bytes(paths) ~= nil then
            return true
        end

        local bytes = read_valid_png_bytes({
            local_png_paths.mark,
            'cryonova_mark.png',
            'cryonova_mark'
        }) or get_embedded_png_bytes('mark')

        if bytes == nil or load_png_bytes(bytes) == false then
            return false
        end

        local wrote = false

        for i = 1, #paths do
            create_parent_dirs(paths[i])

            if pcall(writefile, paths[i], bytes) then
                wrote = true
            end
        end

        return wrote
    end

    function cryonova_assets.get_mark()
        if cryonova_assets.mark_loading then
            return nil
        end

        if cryonova_assets.mark == nil then
            cryonova_assets.mark = load_png({
                local_png_paths.mark,
                'cryonova_mark.png',
                'cryonova_mark'
            })

            if cryonova_assets.mark == false then
                cryonova_assets.mark = load_embedded_png('mark')
            end

            if cryonova_assets.mark == false then
                cryonova_assets.mark = nil
                load_png_from_url('mark', cdn_urls.mark)
            end
        end

        if cryonova_assets.mark == false then
            return nil
        end

        return cryonova_assets.mark
    end

    function cryonova_assets.get_intro_logo()
        if cryonova_assets.intro_logo_loading then
            return nil
        end

        if cryonova_assets.intro_logo == nil then
            cryonova_assets.intro_logo = load_embedded_png('intro_logo')

            if cryonova_assets.intro_logo == false then
                cryonova_assets.intro_logo = load_png({
                    local_png_paths.intro_logo,
                    'cryonova_intro_logo.png',
                    'cryonova_intro_logo'
                })
            end

            if cryonova_assets.intro_logo == false then
                cryonova_assets.intro_logo = nil
                load_png_from_url('intro_logo', cdn_urls.intro_logo)
            end
        end

        if cryonova_assets.intro_logo == false then
            return nil
        end

        return cryonova_assets.intro_logo
    end
end

if cryonova_assets ~= nil and cryonova_assets.ensure_panorama_mark ~= nil then
    pcall(cryonova_assets.ensure_panorama_mark)
end

local color do
    color = ffi.typeof [[
        struct {
            unsigned char r;
            unsigned char g;
            unsigned char b;
            unsigned char a;
        }
    ]]

    local M = { } do
        M.__index = M

        function M:__tostring()
            return string.format(
                '%i, %i, %i, %i',
                self:unpack()
            )
        end

        function M.lerp(a, b, t)
            return color(
                a.r + t * (b.r - a.r),
                a.g + t * (b.g - a.g),
                a.b + t * (b.b - a.b),
                a.a + t * (b.a - a.a)
            )
        end

        function M:unpack()
            return self.r, self.g, self.b, self.a
        end

        function M:clone()
            return color(self:unpack())
        end

        function M:to_hex()
            return string.format(
                '%02x%02x%02x%02x',
                self:unpack()
            )
        end

        function M:hsv(h, s, v)
            local r, g, b

            h = (h % 1.0) * 360
            s = math.max(0, math.min(s, 1))
            v = math.max(0, math.min(v, 1))

            local c = v * s
            local x = c * (1 - math.abs((h / 60) % 2 - 1))
            local m = v - c

            if h < 60 then
                r, g, b = c, x, 0
            elseif h < 120 then
                r, g, b = x, c, 0
            elseif h < 180 then
                r, g, b = 0, c, x
            elseif h < 240 then
                r, g, b = 0, x, c
            elseif h < 300 then
                r, g, b = x, 0, c
            else
                r, g, b = c, 0, x
            end

            self.r = (r + m) * 255
            self.g = (g + m) * 255
            self.b = (b + m) * 255
            self.a = 255

            return self
        end
    end

    ffi.metatype(color, M)
end

local motion do
    motion = { }

    local function linear(t, b, c, d)
        return c * t / d + b
    end

    local function get_deltatime()
        return globals.frametime()
    end

    local function solve(easing_fn, prev, new, clock, duration)
        if clock <= 0 then return new end
        if clock >= duration then return new end

        prev = easing_fn(clock, prev, new - prev, duration)

        if type(prev) == 'number' then
            if math.abs(new - prev) < 0.001 then
                return new
            end

            local remainder = prev % 1.0

            if remainder < 0.001 then
                return math.floor(prev)
            end

            if remainder > 0.999 then
                return math.ceil(prev)
            end
        end

        return prev
    end

    function motion.interp(a, b, t, easing_fn)
        easing_fn = easing_fn or linear

        if type(b) == 'boolean' then
            b = b and 1 or 0
        end

        return solve(easing_fn, a, b, get_deltatime(), t)
    end
end

local utils do
    utils = { }

    function utils.clamp(x, min, max)
        return math.max(min, math.min(x, max))
    end

    function utils.lerp(a, b, t)
        return a + t * (b - a)
    end

    function utils.inverse_lerp(a, b, x)
        return (x - a) / (b - a)
    end

    function utils.map(x, in_min, in_max, out_min, out_max, should_clamp)
        if should_clamp then
            x = utils.clamp(x, in_min, in_max)
        end

        local rel = utils.inverse_lerp(in_min, in_max, x)
        local value = utils.lerp(out_min, out_max, rel)

        return value
    end

    function utils.normalize(x, min, max)
        local d = max - min

        while x < min do
            x = x + d
        end

        while x > max do
            x = x - d
        end

        return x
    end

    function utils.trim(str)
        return str
    end

    function utils.from_hex(hex)
        hex = string.gsub(hex, '#', '')

        local r = tonumber(string.sub(hex, 1, 2), 16)
        local g = tonumber(string.sub(hex, 3, 4), 16)
        local b = tonumber(string.sub(hex, 5, 6), 16)
        local a = tonumber(string.sub(hex, 7, 8), 16)

        return r, g, b, a or 255
    end

    function utils.to_hex(r, g, b, a)
        return string.format('%02x%02x%02x%02x', r, g, b, a)
    end

    function utils.event_callback(event_name, callback, value)
        local fn = value == false
            and client.unset_event_callback
            or client.set_event_callback

        fn(event_name, callback)
    end

    function utils.get_eye_position(ent)
        local origin_x, origin_y, origin_z = entity.get_origin(ent)
        local offset_x, offset_y, offset_z = entity.get_prop(ent, 'm_vecViewOffset')

        if origin_x == nil or offset_x == nil then
            return nil
        end

        local eye_pos_x = origin_x + offset_x
        local eye_pos_y = origin_y + offset_y
        local eye_pos_z = origin_z + offset_z

        return eye_pos_x, eye_pos_y, eye_pos_z
    end

    function utils.get_player_weapons(ent)
        local weapons = { }

        for i = 0, 63 do
            local weapon = entity.get_prop(
                ent, 'm_hMyWeapons', i
            )

            if weapon == nil then
                goto continue
            end

            table.insert(weapons, weapon)
            ::continue::
        end

        return weapons
    end

    function utils.get_player_kd(player)
        if player == nil then
            return nil
        end

        local player_resource = entity.get_player_resource()

        if player_resource == nil then
            return nil
        end

        local kills = entity.get_prop(player_resource, 'm_iKills', player)
        local deaths = entity.get_prop(player_resource, 'm_iDeaths', player)

        if deaths > 0 then
            return kills / deaths
        end

        return kills
    end

    function utils.closest_ray_point(a, b, p, should_clamp)
        local ray_delta = p - a
        local line_delta = b - a

        local lengthsqr = line_delta.x * line_delta.x + line_delta.y * line_delta.y
        local dot_product = ray_delta.x * line_delta.x + ray_delta.y * line_delta.y

        local t = dot_product / lengthsqr

        if should_clamp then
            if t <= 0.0 then
                return a
            end

            if t >= 1.0 then
                return b
            end
        end

        return a + t * line_delta
    end

    function utils.extrapolate(pos, vel, ticks)
        return pos + vel * (ticks * globals.tickinterval())
    end

    function utils.random_int(min, max)
        if min > max then
            min, max = max, min
        end

        return client.random_int(min, max)
    end

    function utils.random_float(min, max)
        if min > max then
            min, max = max, min
        end

        return client.random_float(min, max)
    end

    function utils.find_signature(module_name, pattern, offset)
        local match = client.find_signature(module_name, pattern)

        if match == nil then
            return nil
        end

        if offset ~= nil then
            local address = ffi.cast('char*', match)
            address = address + offset

            return address
        end

        return match
    end
end

local globalvars do
    globalvars = { }

    local globalvars_t = ffi.typeof [[
        struct {
            float   realtime;                     // 0x0000
            int     framecount;                   // 0x0004
            float   absoluteframetime;            // 0x0008
            float   absoluteframestarttimestddev; // 0x000C
            float   curtime;                      // 0x0010
            float   frametime;                    // 0x0014
            int     max_clients;                  // 0x0018
            int     tickcount;                    // 0x001C
            float   interval_per_tick;            // 0x0020
            float   interpolation_amount;         // 0x0024
            int     simTicksThisFrame;            // 0x0028
            int     network_protocol;             // 0x002C
            void*   pSaveData;                    // 0x0030
            bool    m_bClient;                    // 0x0031
            bool    m_bRemoteClient;              // 0x0032
        } ***
    ]]

    local globalvars_ptr = utils.find_signature(
        'client.dll', '\xA1\xCC\xCC\xCC\xCC\x5E\x8B\x40\x10', 0x1
    )

    if globalvars_ptr == nil then
        error 'Unable to find CGlobalVarsBase'
    end

    globalvars = ffi.cast(globalvars_t, globalvars_ptr)[0][0]
end

local ilocalize do
