                local alpha_resolver = ref.alpha_resolver do
                    menu_logic.set(alpha_resolver.enabled, true)
                    menu_logic.set(alpha_resolver.defensive, true)
                    menu_logic.set(alpha_resolver.backtrack, true)
                    menu_logic.set(alpha_resolver.flick, true)

                    if alpha_resolver.enabled:get() then
                        local resolver_mode = alpha_resolver.mode:get()

                        menu_logic.set(alpha_resolver.mode, true)
                        menu_logic.set(alpha_resolver.debug_indicator, true)
                        menu_logic.set(alpha_resolver.debug_line, true)
                        menu_logic.set(alpha_resolver.debug_max_fov, true)
                        menu_logic.set(alpha_resolver.debug_accent, true)

                        if resolver_mode == 'Sauron' then
                            menu_logic.set(alpha_resolver.sauron_adaptive_weapons, true)

                            if alpha_resolver.sauron_adaptive_weapons:get() then
                                menu_logic.set(alpha_resolver.sauron_weapons, true)
                            end
                        end
                    end

                    if alpha_resolver.backtrack:get() then
                        menu_logic.set(alpha_resolver.warning, true)
                    end

                    menu_logic.set(alpha_resolver.separator, true)
                end

                local is_hitchance = ref.hitchance.enabled:get() do
                    menu_logic.set(ref.hitchance.enabled, true)

                    if not is_hitchance then
                        goto continue
                    end

                    menu_logic.set(ref.hitchance.separator, true)

                    local weapon = ref.hitchance.weapon:get()
                    menu_logic.set(ref.hitchance.weapon, true)

                    local items = ref.hitchance[weapon]

                    if items == nil then
                        goto continue
                    end

                    local options = items.options:get()
                    menu_logic.set(items.options, true)

                    for i = 1, #options do
                        local option = options[i]
                        local option_items = items[option]

                        if option_items ~= nil then
                            menu_logic.set(option_items.value, true)

                            if option_items.distance ~= nil then
                                menu_logic.set(option_items.distance, true)
                            end
                        end
                    end

                    if items.options:get 'Hotkey' then
                        menu_logic.set(ref.hitchance.hotkey, true)
                        menu_logic.set(ref.hitchance.indicator_text, true)
