                menu_logic.set(ref.salvatore_quick_switch.enabled, true)

                local jump_scout_assist = ref.jump_scout_assist do
                    menu_logic.set(jump_scout_assist.enabled, true)

                    if jump_scout_assist.enabled:get() then
                        menu_logic.set(jump_scout_assist.auto_scope, true)
                        menu_logic.set(jump_scout_assist.warning, true)
                        menu_logic.set(jump_scout_assist.separator, true)
