                    value
                )
            end

            local callbacks do
                local function on_enabled(item)
                    update_event_callbacks(item:get())
                end

                ref.enabled:set_callback(
                    on_enabled, true
                )
            end
        end

        local salvatore_quick_switch do
            local ref = resource.main.ragebot.salvatore_quick_switch

            local function restore_values()
                override.unset(software.misc.miscellaneous.quick_switch)
                ui.set_enabled(software.misc.miscellaneous.quick_switch, true)
            end

            local function update_values()
                override.set(software.misc.miscellaneous.quick_switch, false)
                ui.set_enabled(software.misc.miscellaneous.quick_switch, false)
            end

            local function on_shutdown()
                restore_values()
            end

            local function on_grenade_thrown(e)
                local me = entity.get_local_player()
                if me == nil then return end

                local uid = e and e.userid
                if uid == nil then return end

                if client.userid_to_entindex(uid) ~= me then return end

                client.delay_call(globals.tickinterval(), client.exec, "slot3; slot2; slot1")
            end

            local function on_weapon_fire(e)
                local me = entity.get_local_player()
                if me == nil then return end

                local uid = e and e.userid
                if uid == nil then return end

                if e.weapon ~= 'weapon_taser' then return end

                if cvar.sv_infinite_ammo and cvar.sv_infinite_ammo:get_int() == 1 then return end

                if client.userid_to_entindex(uid) ~= me then return end

                client.exec('slot3; slot2; slot1')
            end

            local function update_event_callbacks(value)
                if not value then
                    restore_values()
                end

                utils.event_callback('shutdown', on_shutdown, value)
                utils.event_callback('grenade_thrown', on_grenade_thrown, value)
                utils.event_callback('weapon_fire', on_weapon_fire, value)

                if value then
                    update_values()
                end
            end

            local callbacks do
                local function on_enabled(item)
                    update_event_callbacks(item:get())
                end

                ref.enabled:set_callback(on_enabled, true)
            end
        end

        local jump_scout_assist do
            local ref = resource.main.ragebot.jump_scout_assist
            local IN_ATTACK = bit.lshift(1, 0)
            local IN_ATTACK2 = bit.lshift(1, 11)
            local IN_SPEED = bit.lshift(1, 17)
            local FL_ONGROUND = 1
            local ADAPTIVE_STRENGTH = 0.35
            local ADAPTIVE_MAX_SPEED = 220
            local was_slow_motion_forced = false
            local visible_hitboxes = { 0, 3, 5 }

            local function is_scout(weapon)
                if weapon == nil then return false end

                local weapon_info = csgo_weapons(weapon)
                return weapon_info ~= nil and weapon_info.idx == 40
            end

            local function has_visible_enemy(me)
                local eye_x, eye_y, eye_z = client.eye_position()
                if eye_x == nil then return false end

                local enemies = entity.get_players(true)
                for i = 1, #enemies do
                    local enemy = enemies[i]

                    if not entity.is_dormant(enemy) and entity.is_alive(enemy) then
                        for j = 1, #visible_hitboxes do
                            local x, y, z = entity.hitbox_position(enemy, visible_hitboxes[j])

                            if x ~= nil then
                                local fraction, entindex = client.trace_line(me, eye_x, eye_y, eye_z, x, y, z)
                                if fraction == 1 or entindex == enemy then
                                    return true
                                end
                            end
                        end
                    end
                end

                return false
            end

            local function force_slow_motion(value)
                local slow_motion = software.antiaimbot.other.slow_motion

                if value then
                    override.set(slow_motion[1], true)
                    override.set(slow_motion[2], 'Always on')
                    was_slow_motion_forced = true
                    return
                end

                if was_slow_motion_forced then
                    override.unset(slow_motion[2])
                    override.unset(slow_motion[1])
                    was_slow_motion_forced = false
                end
            end

            local function should_assist()
                local me = entity.get_local_player()
                if me == nil or not entity.is_alive(me) then return false end

                local flags = entity.get_prop(me, 'm_fFlags') or 0
                if bit.band(flags, FL_ONGROUND) ~= 0 then return false end

                local weapon = entity.get_player_weapon(me)
                return is_scout(weapon) and has_visible_enemy(me)
            end

            local function on_setup_command(cmd)
                local should_force = should_assist()
                force_slow_motion(should_force)

                if not should_force then return end
                local me = entity.get_local_player()
                if me == nil then return end

                cmd.in_speed = 1
                if cmd.buttons ~= nil then
                    cmd.buttons = bit.bor(cmd.buttons, IN_SPEED)
                end

                local is_attacking = cmd.in_attack == 1 or bit.band(cmd.buttons or 0, IN_ATTACK) ~= 0

                if ref.auto_scope:get() and is_attacking and entity.get_prop(me, 'm_bIsScoped') ~= 1 then
                    cmd.in_attack = 0
                    cmd.in_attack2 = 1

                    if cmd.buttons ~= nil then
                        cmd.buttons = bit.band(cmd.buttons, bit.bnot(IN_ATTACK))
                        cmd.buttons = bit.bor(cmd.buttons, IN_ATTACK2)
                    end
                end

                if not is_attacking then return end

                local vx, vy = entity.get_prop(me, 'm_vecVelocity')
                if vx == nil or vy == nil then return end

                local speed = math.sqrt(vx * vx + vy * vy)
                if speed < 2 then return end

                local slow_amount = utils.clamp((speed - ADAPTIVE_MAX_SPEED) / math.max(speed, 1), 0, 1)
                if slow_amount <= 0 then return end

                slow_amount = slow_amount * ADAPTIVE_STRENGTH

                local yaw = math.rad(cmd.yaw or 0)
                local forward_x, forward_y = math.cos(yaw), math.sin(yaw)
                local right_x, right_y = -forward_y, forward_x
                local wish_x = -vx * slow_amount
                local wish_y = -vy * slow_amount

                cmd.forwardmove = (cmd.forwardmove or 0) + utils.clamp(wish_x * forward_x + wish_y * forward_y, -450, 450)
                cmd.sidemove = (cmd.sidemove or 0) + utils.clamp(wish_x * right_x + wish_y * right_y, -450, 450)

                cmd.in_forward = cmd.forwardmove > 1 and 1 or 0
                cmd.in_back = cmd.forwardmove < -1 and 1 or 0
                cmd.in_moveright = cmd.sidemove > 1 and 1 or 0
                cmd.in_moveleft = cmd.sidemove < -1 and 1 or 0
            end

            local callbacks do
                local function on_enabled(item)
                    local value = item:get()

                    if not value then
                        force_slow_motion(false)
                    end

                    utils.event_callback('setup_command', on_setup_command, value)
                    utils.event_callback('shutdown', force_slow_motion, value)
                end

                ref.enabled:set_callback(on_enabled, true)
            end
        end

        local grimoire_prediction do
            local ref = resource.main.ragebot.grimoire_prediction
            local backup = nil

            local interp_values = {
                Disabled = 0.015625,
                Medium = 0.028000,
                Maximum = 0.029125,
                Extreme = 0.031000
            }

            local function backup_values()
                if backup ~= nil then
                    return
                end

                backup = {
                    interp = cvar.cl_interp:get_float(),
                    interp_ratio = cvar.cl_interp_ratio:get_int(),
                    interpolate = cvar.cl_interpolate:get_int()
                }
            end

            local function restore_values()
                if backup == nil then
                    return
                end

                cvar.cl_interp:set_float(backup.interp)
                cvar.cl_interp_ratio:set_int(backup.interp_ratio)
                cvar.cl_interpolate:set_int(backup.interpolate)

                backup = nil
            end

            local function apply_safe_enabled()
                backup_values()
                cvar.cl_interpolate:set_int(0)
                cvar.cl_interp_ratio:set_int(1)
            end

            local function apply_safe_restore()
                if backup == nil then
                    return
                end

                cvar.cl_interp_ratio:set_int(2)
                cvar.cl_interpolate:set_int(1)
            end

            local function get_weapon_group(weapon)
                local weapon_info = csgo_weapons(weapon)

                if weapon_info == nil then
                    return nil
                end

                local weapon_index = weapon_info.idx

                if weapon_index == 9 then
                    return 'AWP'
                end

                if weapon_index == 40 then
                    return 'Scout'
                end

                if weapon_index == 11 or weapon_index == 38 then
                    return 'Auto Snipers'
                end

                if weapon_index == 1 or weapon_index == 64 then
                    return 'R8'
                end

                return nil
            end

            local function apply_low_ping(weapon_group)
                local item = ref[weapon_group]
                if item == nil then
                    return
                end

                local interp = interp_values[item:get()]
                if interp == nil then
                    return
                end

                cvar.cl_interpolate:set_int(0)
                cvar.cl_interp_ratio:set_int(1)
                cvar.cl_interp:set_float(interp)
            end

            local function apply_high_ping()
                cvar.cl_interp:set_float(0.020000)
                cvar.cl_interp_ratio:set_int(0)
                cvar.cl_interpolate:set_int(0)
            end

            local function on_shutdown()
                restore_values()
            end

            local function on_setup_command()
                if ref.mode:get() ~= 'Legacy' then
                    return
                end

                if not ref.hotkey:get() then
                    restore_values()
                    return
                end

                local me = entity.get_local_player()
                if me == nil or not entity.is_alive(me) then
                    restore_values()
                    return
                end

                local weapon = entity.get_player_weapon(me)
                if weapon == nil then
                    restore_values()
                    return
                end

                backup_values()

                if ref.ping:get() == 'High' then
                    apply_high_ping()
                    return
                end

                local weapon_group = get_weapon_group(weapon)
                if weapon_group == nil then
                    restore_values()
                    return
                end

                apply_low_ping(weapon_group)
            end

            local function on_pre_render()
                if ref.mode:get() ~= 'Safe' then
                    return
                end

                if not ref.hotkey:get() then
                    restore_values()
                    return
                end

                apply_safe_enabled()
            end

            local function on_paint_ui()
                if ref.mode:get() ~= 'Safe' then
                    return
                end

                if not ref.hotkey:get() then
                    restore_values()
                    return
                end

                apply_safe_restore()
            end

            local callbacks do
                local function on_enabled(item)
                    local value = item:get()

                    if not value then
                        restore_values()
                    end

                    utils.event_callback('setup_command', on_setup_command, value)
                    utils.event_callback('pre_render', on_pre_render, value)
                    utils.event_callback('paint_ui', on_paint_ui, value)
                    utils.event_callback('shutdown', on_shutdown, value)
                end

                ref.enabled:set_callback(on_enabled, true)

                ref.mode:set_callback(function()
                    restore_values()
                end)
            end
        end

        local far_teleport do
            local ref = resource.main.ragebot.far_teleport

            local ref_double_tap = {
                ui.reference('Rage', 'Aimbot', 'Double tap')
            }

            local last_command = nil
            local last_tickbase = nil
            local tickbase_delta = 0
            local triggered = false
            local extended = false

            local function reset_state()
                last_command = nil
                last_tickbase = nil
                tickbase_delta = 0
                triggered = false
                extended = false
            end

            local function is_double_tap_defensive()
                return ref_double_tap[3] ~= nil and ui.get(ref_double_tap[1]) and ui.get(ref_double_tap[2]) and ui.get(ref_double_tap[3]) == 'Defensive'
            end

            local function has_hittable_enemy()
                local enemies = entity.get_players(true)

                for i = 1, #enemies do
                    local esp_data = entity.get_esp_data(enemies[i])

                    if esp_data ~= nil and bit.band(esp_data.flags or 0, bit.lshift(1, 11)) ~= 0 then
                        return true
                    end
                end

                return false
            end

            local function should_prime(cmd)
                if triggered then
                    return false
                end

                local is_moving = (
                    cmd.in_forward == 1 or
                    cmd.in_back == 1 or
                    cmd.in_moveleft == 1 or
                    cmd.in_moveright == 1 or
                    cmd.in_jump == 1
                )

                if not is_moving then
                    return false
                end

                if ref.hotkey:get() then
                    return true
                end

                return ref.hittable:get() and has_hittable_enemy()
            end

            local function is_grenade_equipped()
                local me = entity.get_local_player()
                if me == nil then
                    return false
                end

                local weapon = entity.get_player_weapon(me)
                local weapon_info = weapon ~= nil and csgo_weapons(weapon) or nil

                return weapon_info ~= nil and weapon_info.type == 'grenade'
            end

            local function on_run_command(cmd)
                last_command = cmd.command_number
            end

            local function on_predict_command(cmd)
                if cmd.command_number ~= last_command then
                    return
                end

                last_command = nil

                local me = entity.get_local_player()
                if me == nil then
                    return
                end

                local tickbase = entity.get_prop(me, 'm_nTickBase')
                if tickbase == nil then
                    return
                end

                if last_tickbase ~= nil then
                    tickbase_delta = tickbase - last_tickbase
                end

                last_tickbase = math.max(tickbase, last_tickbase or 0)
            end

            local function on_setup_command(cmd)
                if (cmd.weaponselect or 0) ~= 0 then
                    cmd.force_defensive = true
                end

                if not is_double_tap_defensive() then
                    triggered = false
                    extended = false
                    return
                end

                if should_prime(cmd) then
                    triggered = true
                end

                if not triggered then
                    return
                end

                cmd.force_defensive = true

                if tickbase_delta >= 14 then
                    extended = true
                end

                if (extended and tickbase_delta == 0) or is_grenade_equipped() then
                    ui.set(ref_double_tap[1], false)
                    client.delay_call(0.3, ui.set, ref_double_tap[1], true)

                    triggered = false
                    extended = false
                end
            end

            local function on_paint()
                if triggered then
                    local r, g, b = extended and 255 or 143, extended and 0 or 194, extended and 50 or 21
                    renderer.indicator(r, g, b, 255, 'FAR TELEPORT')
                elseif ref.hotkey:get() or ref.hittable:get() then
                    renderer.indicator(255, 255, 255, 220, 'FAR TELEPORT READY')
                end
            end

            local function update_event_callbacks(value)
                if not value then
                    reset_state()
                end

                utils.event_callback('run_command', on_run_command, value)
                utils.event_callback('predict_command', on_predict_command, value)
                utils.event_callback('level_init', reset_state, value)
                utils.event_callback('setup_command', on_setup_command, value)
                utils.event_callback('paint', on_paint, value)
            end

            local callbacks do
                local function on_enabled(item)
                    update_event_callbacks(item:get())
                end

                ref.enabled:set_callback(on_enabled, true)
            end
        end

        local hitchance do
            local ref = resource.main.ragebot.hitchance
            local ref_force_lethal = resource.main.ragebot.force_lethal

            local shared = session.hitchance

            local UNITS_TO_FOOT = 0.0254 * 3.28084

            local ref_hit_chance = ui.reference(
                'Rage', 'Aimbot', 'Minimum hit chance'
            )

            local function get_distance(player, target)
                if player == nil or target == nil then
                    return nil
                end

                local player_origin = vector(entity.get_origin(player))
                local target_origin = vector(entity.get_origin(target))

                return (target_origin - player_origin):length()
            end

            local function get_value(me, weapon_type, items)
                local threat = client.current_threat()

                local force_lethal_value = nil do
                    local is_double_tap = (
                        software.is_double_tap_active()
                        and exploit.get().shift
                    )

                    if ref_force_lethal.enabled:get() and not is_double_tap then
                        local items = ref_force_lethal[weapon_type]

                        if items ~= nil and items.hitchance ~= nil then
                            local value = items.hitchance:get()

                            if value ~= -1 then
                                force_lethal_value = value
                            end
                        end
                    end
                end

                if items.options:get 'Hotkey' and ref.hotkey:get() then
                    shared.updated_hotkey = true
                    return items['Hotkey'].value:get()
                end

                if items.options:get 'Crouch' then
                    local is_crouched = (
                        localplayer.is_onground and
                        localplayer.is_crouched and
                        not software.is_duck_peek_assist()
                    )

                    if is_crouched then
                        return items['Crouch'].value:get()
                    end
                end

                if items.options:get 'Peek Assist' and software.is_quick_peek_assist() then
                    return items['Peek Assist'].value:get()
                end

                if items.options:get 'No Scope' then
                    local goal_distance = items['No Scope'].distance:get()
                    local hitchance_value = items['No Scope'].value:get()

                    if goal_distance == 101 then
                        return hitchance_value
                    end

                    local distance = get_distance(me, threat)

                    if distance ~= nil and (distance * UNITS_TO_FOOT) <= goal_distance then
                        return hitchance_value
                    end
                end

                if items.options:get 'In Air' and not localplayer.is_onground then
                    return items['In Air'].value:get()
                end

                if force_lethal_value ~= nil then
                    return force_lethal_value
                end
            end

            local function get_weapon_type(weapon)
                local weapon_info = csgo_weapons(weapon)

                if weapon_info == nil then
                    return nil
                end

                local weapon_type = weapon_info.type
                local weapon_index = weapon_info.idx

                if weapon_type == 'pistol' then
                    if weapon_index == 1 then
                        return 'Desert Eagle'
                    end

                    if weapon_index == 64 then
                        return 'Revolver R8'
                    end

                    return 'Pistols'
                end

                if weapon_type == 'sniperrifle' then
                    if weapon_index == 40 then
                        return 'Scout'
                    end

                    if weapon_index == 9 then
                        return 'AWP'
                    end

                    return 'Auto Snipers'
                end

                return nil
            end

            local function update_hitchance()
                local me = entity.get_local_player()

                if me == nil then
                    return
                end

                local weapon = entity.get_player_weapon(me)

                if weapon == nil then
                    return
                end

                local weapon_type = get_weapon_type(weapon)

                if weapon_type == nil then
                    return
                end

                local items = ref[weapon_type]

                if items == nil then
                    return
                end

                local value = get_value(
                    me, weapon_type, items
                )

                if value == nil then
                    return
                end

                ragebot.set(ref_hit_chance, value)
                shared.updated_this_tick = true
            end

            local function on_shutdown()
                ragebot.unset(ref_hit_chance)
            end

            local function on_run_command()
                shared.updated_hotkey = false
                shared.updated_this_tick = false

                update_hitchance()
            end

            local function on_finish_command()
                ragebot.unset(ref_hit_chance)
            end

            local function on_paint()
                local me = entity.get_local_player()

                if me == nil or not entity.is_alive(me) then
                    return
                end

                local should_render = (
                    shared.updated_hotkey and
                    shared.updated_this_tick
                )

                if not should_render then
                    return
                end

                local text = ref.indicator_text:get()

                if text == 'Off' then
                    return
                end

                renderer.indicator(255, 255, 255, 200, text)
            end

            local function on_pre_config_save()
                ragebot.unset(ref_hit_chance)
            end

            local callbacks do
                local function on_enabled(item)
                    local value = item:get()

                    if not value then
                        ragebot.unset(ref_hit_chance)
                    end

                    utils.event_callback(
                        'shutdown',
                        on_shutdown,
                        value
                    )

                    utils.event_callback(
                        'run_command',
                        on_run_command,
                        value
                    )

                    utils.event_callback(
                        'finish_command',
                        on_finish_command,
                        value
                    )

                    utils.event_callback(
                        'paint',
                        on_paint,
                        value
                    )

                    utils.event_callback(
                        'pre_config_save',
                        on_pre_config_save,
                        value
                    )
                end

                ref.enabled:set_callback(
                    on_enabled, true
                )
            end
        end

        local quick_peek_auto_stop do
            local ref = resource.main.ragebot.quick_peek_auto_stop

            local ref_quick_stop = {
                ui.reference('Rage', 'Aimbot', 'Quick stop')
