                        local pct = flag[2]

                        local text_size = vector(
                            renderer.measure_text(
                                text_flags, text
                            )
                        )

                        local rect_size = vector(115, 6)

                        local text_pos = vector(
                            flag_pos.x + 4,
                            flag_pos.y + (ROW_SIZE - text_size.y) / 2
                        )

                        local rect_pos = vector(
                            flag_pos.x + 80,
                            flag_pos.y + (ROW_SIZE - rect_size.y) / 2
                        )

                        renderer.text(
                            text_pos.x, text_pos.y,
                            255, 255, 255, 255,
                            text_flags, nil, text
                        )

                        renderer.rectangle(
                            rect_pos.x, rect_pos.y,
                            rect_size.x, rect_size.y,
                            0, 0, 0, 75
                        )

                        if style == 'Fade' then
                            renderer.gradient(
                                rect_pos.x, rect_pos.y,
                                rect_size.x * pct, rect_size.y,
                                col_secondary.r, col_secondary.g, col_secondary.b, col_secondary.a,
                                col_accent.r, col_accent.g, col_accent.b, col_accent.a, true
                            )
                        end

                        if style == 'Astolfo' then
                            renderer.gradient(
                                rect_pos.x, rect_pos.y,
                                rect_size.x * pct, rect_size.y,
                                250, 80, 130, 255, 25, 158, 255, 255, true
                            )
                        end

                        flag_pos.y = flag_pos.y + ROW_SIZE
                    end
                end

                height = height + (ROW_SIZE * flags_count)

                ex_render.blur(position.x, position.y, width, height)
                ex_render.rectangle_outline(position.x, position.y, width, height, 0, 0, 0, 255, 1)

                window:set_size(vector(width, height))
                window:update()
            end

            local callbacks do
                local function on_enabled(item)
                    local value = item:get()

                    utils.event_callback(
                        'paint_ui',
                        on_paint_ui,
                        value
                    )
                end

                ref.enabled:set_callback(
                    on_enabled, true
                )
            end
        end
        local indicators do
            local ref = resource.render.user_interface.indicators

            local on_paint_ui do
                local SCRIPT_NAME = script.name:lower()
                local SCRIPT_BUILD = script.build:lower()

                local stars = {
                    { '-', '✨', 0, 0, 0.1 },
                    { '-', '✨', -3, 5, 1.3 },
                    { '+', '⋆', -9, -16, 0.4 },
                    { '-', '✨', -1, -1, 0.2 },
                    { '+', '⋆', -3, -10, 1.5 },
                    { '+', '⋆', -6, -15, 0.7 },
                }

                local alpha_value = 0.0
                local align_value = 0.0

                local baim_value = 0.0
                local hc_value = 0.0

                local dt_value = 0.0
                local osaa_value = 0.0

                local charge_value = 0.0

                local function is_grenade(weapon)
                    local weapon_info = csgo_weapons(weapon)

                    if weapon_info == nil then
                        return false
                    end

                    return weapon_info.type == 'grenade'
                end

                local function get_state()
                    local manual_yaw = antiaim.manual_yaw:get()

                    if manual_yaw ~= nil then
                        local str = manual_yaw:upper()

                        return string.format(
                            'MANUAL %s', str
                        )
                    end

                    if software.is_freestanding() then
                        return 'FREESTAND'
                    end

                    if not localplayer.is_onground then
                        if localplayer.is_crouched then
                            return 'AIR-CROUCH'
                        end

                        return 'AIR'
                    end

                    if localplayer.is_crouched then
                        if localplayer.is_moving then
                            return 'CROUCH-MOVE'
                        end

                        return 'CROUCH'
                    end

                    if localplayer.is_moving then
                        if software.is_slow_motion() then
                            return 'SLOWING'
                        end

                        return 'MOVING'
                    end

                    return 'STANDING'
                end

                local function draw_stars(position, r1, g1, b1, a1, r2, g2, b2, a2)
                    local time = -globals.realtime()
                    local x, y = position.x + 4, position.y

                    local sizes, len = { }, #stars
                    local width, height = 0, 0

                    for i = 1, len do
                        local data = stars[i]

                        local measure = vector(
                            renderer.measure_text(data[1], data[2])
                        )

                        width = width + (measure.x + data[3])
                        height = math.max(height, measure.y + data[4])

                        sizes[i] = measure
                    end

                    x = round(x - (width * 0.5) * (1 - align_value))

                    local pct = 0.0
                    local div = 1 / (len - 1)

                    local style = ref.style:get()

                    for i = 1, len do
                        local star = stars[i]
                        local size = sizes[i]

                        local flags = star[1]
                        local text = star[2]

                        local offset_x = star[3]
                        local offset_y = star[4]

                        local phase = star[5]

                        local phase_value = math.sin(time * phase) do
                            phase_value = phase_value * 0.5 + 0.5
                            phase_value = phase_value * 0.5 + 0.3
                        end

                        if style == 'Default' then
                            text = text_anims.gradient(
                                text, (time + pct) * 1.25,
                                r1, g1, b1, a1,
                                r2, g2, b2, a2
                            )
                        end

                        if style == 'Astolfo' then
                            text = text_anims.astolfo(
                                text, (time + pct) * 0.5,
                                0.5, 0.4, 1.0, 0.5
                            )
                        end

                        renderer.text(
                            x + offset_x, y + offset_y,
                            200, 200, 200, a1 * phase_value,
                            flags, nil, text
                        )

                        x = x + size.x + offset_x

                        pct = pct + div
                    end

                    position.y = position.y + height * 0.5
                end

                local function draw_state(position, r, g, b, a, alpha)
                    local text, flags = get_state(), '-'

                    local measure = vector(
                        renderer.measure_text(flags, text)
                    )

                    local x, y = position.x, position.y do
                        x = round(x - (measure.x * 0.5) * (1 - align_value))
                    end

                    renderer.text(x, y, r, g, b, a * alpha, flags, nil, text)

                    position.y = position.y + round(measure.y)
                end

                -- ============================================================
                -- НОВАЯ ФУНКЦИЯ draw_title с разделением script_name и script_build
                -- ============================================================
                local function draw_title(position, r1, g1, b1, a1, r2, g2, b2, a2)
                    local time = -globals.realtime()
                    local style = ref.style:get()

                    -- Разделяем на название и билд
                    local title_text = SCRIPT_NAME:upper()
                    local build_text = SCRIPT_BUILD:upper()

                    if style == 'Mini' then
                        title_text = 'REVISION'
                        build_text = ''
                    end

                    -- Измеряем оба текста + точку
                    local title_measure = vector(renderer.measure_text('-', title_text))
                    local dot_measure = vector(renderer.measure_text('-', '.'))
                    local build_measure = vector(renderer.measure_text('-', build_text))

                    -- Общая ширина для центрирования
                    local total_width = title_measure.x + dot_measure.x + build_measure.x

                    local x, y = position.x, position.y do
                        x = round(x - (total_width * 0.5) * (1 - align_value))
                    end

                    -- Сохраняем начальную позицию для Mini стиля
                    local start_x = x

                    if style == 'Default' then
                        -- 1. Рисуем название (серый/белый)
                        renderer.text(x, y, 220, 220, 220, a1, '-', nil, title_text)
                        x = x + title_measure.x

                        -- 2. Рисуем точку (серая)
                        renderer.text(x, y, 220, 220, 220, a1, '-', nil, '.')
                        x = x + dot_measure.x

                        -- 3. Рисуем билд с градиентом
                        local gradient_text = text_anims.gradient(
                            build_text, time * 1.25,
                            r1, g1, b1, a1,
                            r2, g2, b2, a2
                        )
                        renderer.text(x, y, 255, 255, 255, a1, '-', nil, gradient_text)

                    elseif style == 'Astolfo' then
                        -- 1. Рисуем название (серый)
                        renderer.text(x, y, 220, 220, 220, a1, '-', nil, title_text)
                        x = x + title_measure.x

                        -- 2. Рисуем точку (серая)
                        renderer.text(x, y, 220, 220, 220, a1, '-', nil, '.')
                        x = x + dot_measure.x

                        -- 3. Рисуем билд с астольфо анимацией
                        local astolfo_text = text_anims.astolfo(
                            build_text, time * 0.5,
                            0.5, 0.4, 1.0, 0.5
                        )
                        renderer.text(x, y, 255, 255, 255, a1, '-', nil, astolfo_text)

                    else -- Mini стиль
                        -- Оставляем как было: только "REVISION" с подчеркиванием
                        local measure = vector(renderer.measure_text('-', title_text))
                        local line = round((measure.x * 0.5) * alpha_value)
                        local mid = start_x + round(measure.x * 0.5)
                        local gy = y + round(measure.y * 0.65)

                        renderer.gradient(mid - line, gy, line, 1, r2, g2, b2, 0, r1, g1, b1, a1, true)
                        renderer.gradient(mid, gy, line, 1, r1, g1, b1, a1, r2, g2, b2, 0, true)

                        renderer.text(start_x, y, r1, g1, b1, a1, '-', nil, title_text)
                    end

                    -- Обновляем позицию Y (берем максимальную высоту)
                    position.y = position.y + math.max(title_measure.y, build_measure.y)
                end

                local function draw_double_tap(position, r, g, b, a, value, alpha)
                    local text, flags = 'DT', '-'

                    local measure = vector(
                        renderer.measure_text(flags, text)
                    )

                    local x, y = position.x, position.y do
                        x = round(x - (measure.x * 0.5) * (1 - align_value))
                    end

                    r = utils.lerp(255, r, charge_value)
                    g = utils.lerp(0, g, charge_value)
                    b = utils.lerp(50, b, charge_value)

                    a = a * value * alpha

                    renderer.text(x, y, r, g, b, a, flags, nil, text)

                    position.y = position.y + round(measure.y * value)
                end

                local function draw_onshot_antiaim(position, r, g, b, a, value, alpha)
                    local text, flags = 'OSAA', '-'

                    local measure = vector(
                        renderer.measure_text(flags, text)
                    )

                    local x, y = position.x, position.y do
                        x = round(x - (measure.x * 0.5) * (1 - align_value))
                    end

                    a = a * value * alpha

                    renderer.text(x, y, r, g, b, a, flags, nil, text)

                    position.y = position.y + round(measure.y * value)
                end

                local function draw_body_aim(position, r, g, b, a, value, alpha)
                    local text, flags = 'BODY', '-'

                    local measure = vector(
                        renderer.measure_text(flags, text)
                    )

                    local x, y = position.x, position.y do
                        x = round(x - (measure.x * 0.5) * (1 - align_value))
                    end

                    a = a * value * alpha

                    renderer.text(x, y, r, g, b, a, flags, nil, text)

                    position.y = position.y + round(measure.y * value)
                end

                local function draw_hitchance(position, r, g, b, a, value, alpha)
                    local text, flags = 'HC', '-'

                    local measure = vector(
                        renderer.measure_text(flags, text)
                    )

                    local x, y = position.x, position.y do
                        x = round(x - (measure.x * 0.5) * (1 - align_value))
                    end

                    a = a * value * alpha

                    renderer.text(x, y, r, g, b, a, flags, nil, text)

                    position.y = position.y + round(measure.y * value)
                end

                local mini_measure_cache = { }

                local function draw_mini_item(position, text, r, g, b, a, value)
                    local flags = '-'
                    local measure = mini_measure_cache[text]

                    if measure == nil then
                        measure = vector(
                            renderer.measure_text(flags, text)
                        )

                        mini_measure_cache[text] = measure
                    end

                    local x, y = position.x, position.y do
                        x = round(x - (measure.x * 0.5) * (1 - align_value))
                    end

                    local item_alpha = a * alpha_value * (value or 1)

                    renderer.text(x, y, r, g, b, item_alpha, flags, nil, text)

                    position.y = position.y + round(measure.y * (value or 1))
                end

                local function draw_mini_pack(position, r1, g1, b1, a1)

                    if ref.select:get 'State' then
                        draw_mini_item(position, get_state(), 250, 250, 250, 125, 1)
                    end

                    if ref.select:get 'Double tap' and software.is_double_tap_active() then
                        local charge = math.floor(utils.clamp(charge_value, 0, 1) * 100 + 0.5)
                        draw_mini_item(position, 'DT ' .. tostring(charge) .. '%', r1, g1, b1, math.max(a1, 175), math.max(dt_value, 0.35))
                    end

                    if ref.select:get 'Hide shots' and software.is_on_shot_antiaim_active() then
                        draw_mini_item(position, 'OSAA', 250, 250, 250, 175, math.max(osaa_value, 0.35))
                    end

                    if ref.select:get 'Body aim' and ui.get(software.ragebot.aimbot.force_body_aim) then
                        draw_mini_item(position, 'BODY', 250, 250, 250, 175, math.max(baim_value, 0.35))
                    end

                    if ref.select:get 'Hitchance' and (session.hitchance.updated_hotkey and session.hitchance.updated_this_tick) then
                        draw_mini_item(position, 'HC', 250, 250, 250, 175, math.max(hc_value, 0.35))
                    end

                    if software.is_override_minimum_damage() then
                        draw_mini_item(position, 'DMG ' .. tostring(software.get_override_damage()), 250, 250, 250, 175, 1)
                    end

                    if software.is_freestanding() then
                        draw_mini_item(position, 'FS', 250, 250, 250, 160, 1)
                    end

                    if software.is_quick_peek_assist() then
                        draw_mini_item(position, 'PEEK', 250, 250, 250, 160, 1)
                    end

                    if software.is_duck_peek_assist() then
                        draw_mini_item(position, 'FD', 250, 250, 250, 160, 1)
                    end
                end

                local command_measure_cache = { }

                local function command_text_size(text)
                    local measure = command_measure_cache[text]

                    if measure == nil then
                        measure = vector(renderer.measure_text('-', text))
                        command_measure_cache[text] = measure
                    end

                    return measure
                end

                local function add_command_item(items, label, active, r, g, b, a)
                    items[#items + 1] = {
                        label = label,
                        active = active,
                        r = r,
                        g = g,
                        b = b,
                        a = a
                    }
                end

                local function draw_command_bar(position, r1, g1, b1, a1, r2, g2, b2, a2)
                    local alpha = utils.clamp(alpha_value, 0, 1)

                    if alpha <= 0 then
                        return
                    end

                    local items = { }

                    -- Используем разделенный title для Command Bar
                    local title_text = SCRIPT_NAME:upper()
                    local build_text = SCRIPT_BUILD:upper()
                    local full_title = title_text .. '.' .. build_text
                    
                    add_command_item(items, full_title, true, r1, g1, b1, 235)

                    if ref.select:get 'State' then
                        add_command_item(items, get_state(), true, 230, 230, 235, 185)
                    end

                    if ref.select:get 'Double tap' then
                        local charge = math.floor(utils.clamp(charge_value, 0, 1) * 100 + 0.5)
                        local active = software.is_double_tap_active()
                        add_command_item(items, 'DT ' .. tostring(charge), active, active and r1 or 145, active and g1 or 145, active and b1 or 145, active and 220 or 105)
                    end

                    if ref.select:get 'Hide shots' then
                        local active = software.is_on_shot_antiaim_active()
                        add_command_item(items, 'HS', active, active and 245 or 145, active and 245 or 145, active and 245 or 145, active and 205 or 95)
                    end

                    if ref.select:get 'Body aim' then
                        local active = ui.get(software.ragebot.aimbot.force_body_aim)
                        add_command_item(items, 'BODY', active, active and 255 or 145, active and 215 or 145, active and 120 or 145, active and 220 or 95)
                    end

                    if ref.select:get 'Hitchance' then
                        local active = session.hitchance.updated_hotkey and session.hitchance.updated_this_tick
                        add_command_item(items, 'HC', active, active and 165 or 145, active and 235 or 145, active and 255 or 145, active and 210 or 95)
                    end

                    if software.is_override_minimum_damage() then
                        add_command_item(items, 'DMG ' .. tostring(software.get_override_damage()), true, 255, 255, 255, 220)
                    end

                    if software.is_freestanding() then
                        add_command_item(items, 'FS', true, 190, 225, 255, 210)
                    end

                    if #items == 0 then
                        return
                    end

                    local pad_x, pad_y = 7, 5
                    local row_gap = 1
                    local width = 0
                    local row_height = 0

                    for i = 1, #items do
                        local size = command_text_size(items[i].label)
                        width = math.max(width, size.x)
                        row_height = math.max(row_height, size.y)
                    end

                    width = width + pad_x * 2
                    local height = pad_y * 2 + (#items * row_height) + math.max(#items - 1, 0) * row_gap
                    local x = round(position.x - width * 0.5 + 8 * align_value)
                    local y = round(position.y)
                    local line_alpha = 150 * alpha

                    renderer.gradient(x, y, width * 0.5, 1, r2, g2, b2, 0, r1, g1, b1, line_alpha, true)
                    renderer.gradient(x + width * 0.5, y, width * 0.5, 1, r1, g1, b1, line_alpha, r2, g2, b2, 0, true)

                    local text_x = x + math.floor(width * 0.5)
                    local cursor_y = y + pad_y + math.floor(row_height * 0.5)

                    for i = 1, #items do
                        local item = items[i]
                        local item_alpha = item.a * alpha

                        renderer.text(text_x + 1, cursor_y + 1, 0, 0, 0, 115 * alpha, '-c', 0, item.label)
                        renderer.text(text_x, cursor_y, item.r, item.g, item.b, item_alpha, '-c', 0, item.label)

                        cursor_y = cursor_y + row_height + row_gap
                    end
                end

                local function update_values(me)
                    local is_alive = entity.is_alive(me)
                    local is_scoped = entity.get_prop(me, 'm_bIsScoped') == 1

                    local is_shifting = exploit.get().shift

                    local is_double_tap = software.is_double_tap_active()
                    local is_onshot_aa = software.is_on_shot_antiaim_active()

                    local is_hitchance_override = (
                        session.hitchance.updated_hotkey and
                        session.hitchance.updated_this_tick
                    )

                    local is_force_baim_override = ui.get(
                        software.ragebot.aimbot.force_body_aim
                    )

                    local alpha_target = 0.0

                    if is_alive then
                        alpha_target = 1.0

                        local weapon = entity.get_player_weapon(me)

                        if is_scoped or (weapon ~= nil and is_grenade(weapon)) then
                            alpha_target = 0.5
                        end
                    end

                    alpha_value = motion.interp(alpha_value, alpha_target, 0.05)
                    align_value = motion.interp(align_value, is_scoped, 0.05)

                    baim_value = motion.interp(baim_value, is_force_baim_override, 0.05)
                    hc_value = motion.interp(hc_value, is_hitchance_override, 0.05)

                    dt_value = motion.interp(dt_value, is_double_tap, 0.05)
                    osaa_value = motion.interp(osaa_value, is_onshot_aa, 0.05)

                    charge_value = motion.interp(charge_value, is_shifting, 0.05)
                end

                local function draw_indicators()
                    local screen = vector(
                        client.screen_size()
                    )

                    local position = screen * 0.5

                    local r1, g1, b1, a1 = ref.accent_color:get()
                    local r2, g2, b2, a2 = ref.secondary_color:get()

                    position.x = position.x - 1

                    position.x = position.x + math.floor(0.5 + 10 * align_value)
                    position.y = position.y + ref.offset:get()

                    a1 = a1 * alpha_value
                    a2 = a2 * alpha_value
                    local style = ref.style:get()

                    if style == 'Command Bar' then
                        draw_command_bar(position, r1, g1, b1, a1, r2, g2, b2, a2)
                        return
                    end

                    if style ~= 'Mini' and ref.select:get 'Stars' then
                        draw_stars(position, r1, g1, b1, a1, r2, g2, b2, a2)
                    end

                    draw_title(position, r1, g1, b1, a1, r2, g2, b2, a2)

                    if style == 'Mini' then
                        draw_mini_pack(position, r1, g1, b1, a1)
                        return
                    end

                    if ref.select:get 'State' then
                        draw_state(position, 250, 250, 250, 125, alpha_value)
                    end

                    if ref.select:get 'Double tap' then
                        draw_double_tap(position, 250, 250, 250, 175, dt_value, alpha_value)
                    end

                    if ref.select:get 'Hide shots' then
                        draw_onshot_antiaim(position, 250, 250, 250, 175, osaa_value, alpha_value)
                    end

                    if ref.select:get 'Body aim' then
                        draw_body_aim(position, 250, 250, 250, 175, baim_value, alpha_value)
                    end

                    if ref.select:get 'Hitchance' then
                        draw_hitchance(position, 250, 250, 250, 175, hc_value, alpha_value)
                    end
                end

                function on_paint_ui()
                    local me = entity.get_local_player()

                    if me == nil then
                        return
                    end

                    update_values(me)

                    if alpha_value > 0 then
                        draw_indicators()
                    end
                end
            end

            local callbacks do
                local function on_enabled(item)
                    local value = item:get()

                    utils.event_callback(
                        'paint_ui',
                        on_paint_ui,
                        value
                    )
                end

                ref.enabled:set_callback(
                    on_enabled, true
                )
            end
        end

        local manual_arrows do
            local ref = resource.antiaim.hotkeys.manual_yaw

            local COLOR_DISABLED = color(0, 0, 0, 127)

            local function on_draw_classic()
                local me = entity.get_local_player()

                if me == nil or not entity.is_alive(me) then
                    return
                end

                local screen_size = vector(
                    client.screen_size()
                )

                local center = screen_size * 0.5

                local col = color(ref.arrows_color:get())
                local manual = antiaim.manual_yaw:get()

                local padding = ref.arrows_offset:get()

                if manual == 'left' then
                    local text = ''

                    local text_size = vector(
                        renderer.measure_text('+', text)
                    )

                    local text_pos = vector(
                        center.x - text_size.x - padding + 1,
                        center.y - text_size.y * 0.5 - 4.5
                    )

                    renderer.text(text_pos.x, text_pos.y, col.r, col.g, col.b, col.a, '+', nil, text)
                end

                if manual == 'right' then
                    local text = ''

                    local text_size = vector(
                        renderer.measure_text('+', text)
                    )

                    local text_pos = vector(
                        center.x + padding,
                        center.y - text_size.y * 0.5 - 4.5
                    )

                    renderer.text(text_pos.x, text_pos.y, col.r, col.g, col.b, col.a, '+', nil, text)
                end
            end

            local function on_draw_modern()
                local me = entity.get_local_player()

                if me == nil or not entity.is_alive(me) then
                    return
                end

                local screen_size = vector(
                    client.screen_size()
                )

                local center = screen_size * 0.5

                local col = color(ref.arrows_color:get())
                local manual = antiaim.manual_yaw:get()

                local padding = ref.arrows_offset:get()

                if manual == 'left' then
                    local text = '⮜'

                    local text_size = vector(
                        renderer.measure_text('+', text)
                    )

                    local text_pos = vector(
                        center.x - text_size.x - padding + 1,
                        center.y - text_size.y * 0.5 - 1
                    )

                    renderer.text(text_pos.x, text_pos.y, col.r, col.g, col.b, col.a, '+', nil, text)
                end

                if manual == 'right' then
                    local text = '⮞'

                    local text_size = vector(
                        renderer.measure_text('+', text)
                    )

                    local text_pos = vector(
                        center.x + padding,
                        center.y - text_size.y * 0.5 - 1
                    )

                    renderer.text(text_pos.x, text_pos.y, col.r, col.g, col.b, col.a, '+', nil, text)
                end
            end

            local function on_draw_teamskeet()
                local me = entity.get_local_player()

                if me == nil or not entity.is_alive(me) then
                    return
                end

                local screen_size = vector(
                    client.screen_size()
                )

                local center = screen_size * 0.5

                local width = 2
                local height = 18

                local gap = 2

                local peak = math.floor(height * 0.75)
                local padding = ref.arrows_offset:get()

                local manual = antiaim.manual_yaw:get()
                local body_yaw = antiaim.buffer.body_yaw_offset or 0

                local is_left_desync = body_yaw < 0
                local is_right_desync = body_yaw > 0

                local color_arrows = color(ref.arrows_color:get())
                local color_desync = color(ref.desync_color:get())

                -- left
                do
                    local position = center - vector(padding, 0)

                    local rect_size = vector(width, height)
                    local rect_pos = position - vector(rect_size.x, rect_size.y * 0.5)

                    local rect_color = is_left_desync and color_desync or COLOR_DISABLED
                    local poly_color = manual == 'left' and color_arrows or COLOR_DISABLED

                    renderer.rectangle(rect_pos.x, rect_pos.y, rect_size.x, rect_size.y, rect_color:unpack())
                    position.x = position.x - (rect_size.x + gap)

                    local point_0 = vector(position.x, position.y - height * 0.5)
                    local point_1 = vector(position.x, position.y + height * 0.5)
                    local point_2 = vector(position.x - peak, position.y)

                    renderer.triangle(
                        point_0.x, point_0.y,
                        point_1.x, point_1.y,
                        point_2.x, point_2.y,
                        poly_color:unpack()
                    )
                end

                do
                    local position = center + vector(padding + 1, 0)

                    local rect_size = vector(width, height)
                    local rect_pos = position - vector(0, rect_size.y * 0.5)

                    local rect_color = is_right_desync and color_desync or COLOR_DISABLED
                    local poly_color = manual == 'right' and color_arrows or COLOR_DISABLED

                    renderer.rectangle(rect_pos.x, rect_pos.y, rect_size.x, rect_size.y, rect_color:unpack())
                    position.x = position.x + (rect_size.x + gap)

                    local point_0 = vector(position.x, position.y - height * 0.5)
                    local point_1 = vector(position.x, position.y + height * 0.5)
                    local point_2 = vector(position.x + peak, position.y)

                    renderer.triangle(
                        point_0.x, point_0.y,
                        point_1.x, point_1.y,
                        point_2.x, point_2.y,
                        poly_color:unpack()
                    )
                end
            end

            local function update_event_callbacks(value)
                utils.event_callback(
                    'paint_ui',
                    on_draw_classic,
                    value == 'Classic'
                )

                utils.event_callback(
                    'paint_ui',
                    on_draw_modern,
                    value == 'Modern'
                )

                utils.event_callback(
                    'paint_ui',
                    on_draw_teamskeet,
                    value == 'Teamskeet'
                )
            end

            local callbacks do
                local function on_manual_arrows(item)
                    update_event_callbacks(item:get())
                end

                local function on_enabled(item)
                    local value = item:get()

                    if not value then
                        update_event_callbacks(nil)
                    end

                    if value then
                        ref.manual_arrows:set_callback(on_manual_arrows, true)
                    else
                        ref.manual_arrows:unset_callback(on_manual_arrows)
                    end
                end

                ref.enabled:set_callback(
                    on_enabled, true
                )
            end
        end
        local net_graphic do
            local ref = resource.render.user_interface.net_graphic

            local FRAMERATE_AVG_FRAC = 0.9

            local netchannel_t = ffi.typeof [[
                struct {
                    char        pad_0000[24];                    //0x0000
                    int         m_nOutSequenceNr;                //0x0018
                    int         m_nInSequenceNr;                 //0x001C
                    int         m_nOutSequenceNrAck;             //0x0020
                    int         m_nOutReliableState;             //0x0024
                    int         m_nInReliableState;              //0x0028
                    int         m_nChokedPackets;                //0x002C
                    char        pad_0030[108];                   //0x0030
                    int         m_Socket;                        //0x009C
                    int         m_StreamSocket;                  //0x00A0
                    int         m_MaxReliablePayloadSize;        //0x00A4
                    char        pad_00A8[100];                   //0x00A8
                    float       last_received;                   //0x010C
                    float       connect_time;                    //0x0110
                    char        pad_0114[4];                     //0x0114
                    int         m_Rate;                          //0x0118
                    char        pad_011C[4];                     //0x011C
                    float       m_fClearTime;                    //0x0120
                    char        pad_0124[16688];                 //0x0124
                    char        m_Name[32];                      //0x4254
                    size_t      m_ChallengeNr;                   //0x4274
                    float       m_flTimeout;                     //0x4278
                    char        pad_427C[32];                    //0x427C
                    float       m_flInterpolationAmount;         //0x429C
                    float       m_flRemoteFrameTime;             //0x42A0
                    float       m_flRemoteFrameTimeStdDeviation; //0x42A4
                    int         m_nMaxRoutablePayloadSize;       //0x42A8
                    int         m_nSplitPacketSequence;          //0x42AC
                    char        pad_42B0[40];                    //0x42B0
                    bool        m_bIsValveDS;                    //0x42D8
                    char        pad_42D9[65];                    //0x42D9
                }
            ]]

            local GetNetChannelInfo = vtable_bind(
                'engine.dll', 'VEngineClient014', 78, '$*(__thiscall*)(void*)', netchannel_t
            )

            local GetAvgLatency = vtable_thunk(10, 'float(__thiscall*)(void*, int flow)')
            local GetAvgLoss = vtable_thunk(11, 'float(__thiscall*)(void*, int flow)')
            local GetAvgChoke = vtable_thunk(12, 'float(__thiscall*)(void*, int flow)')
            local GetRemoteFramerate = vtable_thunk(25, 'void(__thiscall*)(void*, float *pflFrameTime, float *pflFrameTimeStdDeviation, float *pflFrameStartTimeStdDeviation)')

            local cl_updaterate = cvar.cl_updaterate
            local net_graphholdsvframerate = cvar.net_graphholdsvframerate

            local framerate = 0.0
            local avg_latency = 0.0

            local avg_packet_loss = 0.0
            local avg_packet_choke = 0.0

            local m_flServerFrameComputationTime = ffi.new 'float[1]'
            local m_flServerFramerateStdDeviation = ffi.new 'float[1]'
            local m_flServerFrameStartTimeStdDeviation = ffi.new 'float[1]'

            local font_flags = {
                ['Default'] = '',
                ['Small'] = '-',
                ['Bold'] = 'b'
            }

            local function update_framerate_data()
                framerate = FRAMERATE_AVG_FRAC * framerate + ( 1.0 - FRAMERATE_AVG_FRAC ) * globals.absoluteframetime()

                if framerate <= 0.0 then
                    framerate = 1.0
                end
            end

            local function update_networking_data(nci)
                if nci == nil then
                    return
                end

                GetRemoteFramerate(nci, m_flServerFrameComputationTime, m_flServerFramerateStdDeviation, m_flServerFrameStartTimeStdDeviation)

                avg_latency = GetAvgLatency(nci, 0)

                avg_packet_loss = GetAvgLoss(nci, 1)
                avg_packet_choke = GetAvgChoke(nci, 1)

                if cl_updaterate:get_float() > 0.001 then
                    avg_latency = avg_latency - (0.5 / cl_updaterate:get_float())
                end

                avg_latency = math.max(0.0, avg_latency)
            end

            local function render_net_graphic(nci)
                local offset = ref.offset:get() * 0.01

                local text_font = ref.font:get()
                local text_col = color(ref.color:get())

                local screen = vector(
                    client.screen_size()
                )

                local position = vector(
                    0, screen.y - 59
                )

                -- average net graphic width is 200
                position.x = utils.lerp(60, screen.x - 200 - 60, offset)

                local flags = font_flags[text_font]

                if flags == nil then
                    return
                end

                local list = { } do
                    if ref.display:get 'Framerate' then
                        table.insert(list, string.format(
                            'fps: %5i  var: %4.1f ms  ping: %i ms',
                            1 / framerate,
                            globalvars.absoluteframestarttimestddev * 1000,
                            avg_latency * 1000
                        ))
                    end

                    if nci ~= nil then
                        if ref.display:get 'Connection' then
                            table.insert(list, string.format(
                                'loss: %3i%%  choke: %2i%%',
                                avg_packet_loss * 100,
                                avg_packet_choke * 100
                            ))
                        end

                        if ref.display:get 'Server response' then
                            table.insert(list, string.format(
                                'sv:%5.1f %s%4.1f ms   var: %6.3f ms',
                                m_flServerFrameComputationTime[0] * 1000,
                                net_graphholdsvframerate:get_int() == 1 and '~/' or '+-',
                                m_flServerFramerateStdDeviation[0] * 1000,
                                m_flServerFrameStartTimeStdDeviation[0] * 1000
                            ))
                        end
                    end
                end

                local text = table.concat(list, '\n')

                if flags:find '-' then
                    text = text:upper()
                end

                local text_size = vector(
                    renderer.measure_text(flags, text)
                )

                local text_pos = position - vector(
                    0, text_size.y
                )

                renderer.text(
                    text_pos.x, text_pos.y,
                    text_col.r, text_col.g, text_col.b, text_col.a,
                    flags, nil, text
                )
            end

            local function on_paint()
                local nci = GetNetChannelInfo()

                update_framerate_data()
                update_networking_data(nci)

                render_net_graphic(nci)
            end

            local function update_event_callbacks(value)
                utils.event_callback(
                    'paint',
                    on_paint,
                    value
                )
            end

            local callbacks do
                local function on_enabled(item)
                    update_event_callbacks(item:get())
                end

                ref.enabled:set_callback(
                    on_enabled, true
                )
            end
        end

        local console_color do
            local ref = resource.render.user_interface.console_color

            local ConsoleIsVisible = vtable_bind(
                'engine.dll', 'VEngineClient014', 11, 'bool(__thiscall*)(void*)'
            )

            local materials do
                materials = { }

                local list = {
                    'vgui_white',
                    'vgui/hud/800corner1',
                    'vgui/hud/800corner2',
                    'vgui/hud/800corner3',
                    'vgui/hud/800corner4'
                }

                for i = 1, #list do
                    materials[i] = materialsystem.find_material(list[i])
                end
            end

            local function update(r, g, b, a)
                for i = 1, #materials do
                    local material = materials[i]

                    material:alpha_modulate(a)
                    material:color_modulate(r, g, b)
                end
            end

            local function on_shutdown()
                update(255, 255, 255, 255)
            end

            local function on_pre_render()
                if not ConsoleIsVisible() then
                    update(255, 255, 255, 255)
                else
                    update(ref.color:get())
                end
            end

            local function update_event_callbacks(value)
                if not value then
                    update(255, 255, 255, 255)
                end

                utils.event_callback(
                    'shutdown',
                    on_shutdown,
                    value
                )

                utils.event_callback(
                    'paint_ui',
                    on_pre_render,
                    value
                )
            end

            local callbacks do
                local function on_enabled(item)
                    update_event_callbacks(item:get())
                end

                ref.enabled:set_callback(
                    on_enabled, true
                )
            end
        end

        local damage_indicator do
            local ref = resource.render.user_interface.damage_indicator

            local ref_minimum_damage = ui.reference(
                'Rage', 'Aimbot', 'Minimum damage'
            )

            local ref_override_damage = {
                ui.reference('Rage', 'Aimbot', 'Minimum damage override')
            }

            local font_flags = {
                ['Default'] = '',
                ['Small'] = '-',
                ['Bold'] = 'b'
            }

            local function is_minimum_damage_override()
                return ui.get(ref_override_damage[1])
                    and ui.get(ref_override_damage[2])
            end

            local function get_flags()
                return font_flags[ref.font:get()] or ''
            end

            local function get_aimbot_damage(override)
                if override then
                    return ui.get(ref_override_damage[3])
                end

                return ui.get(ref_minimum_damage)
            end

            local function get_render_damage(override)
                if not override and session.force_lethal.updated_this_tick then
                    return 'FL'
                end

                local damage = get_aimbot_damage(override)

                if damage == 0 then
                    return 'AUTO'
                end

                if damage > 100 then
                    return string.format(
                        '+%d', damage - 100
                    )
                end

                return tostring(damage)
            end

            local function on_paint_ui()
                local me = entity.get_local_player()

                if me == nil or not entity.is_alive(me) then
                    return
                end

                local screen_size = vector(
                    client.screen_size()
                )

                local position = screen_size * 0.5
                local offset = ref.offset:get()

                position.x = position.x + offset
                position.y = position.y - offset

                local r, g, b, a = ref.inactive_color:get()

                local is_override = is_minimum_damage_override()
                local flags, text = get_flags(), get_render_damage(is_override)

                if ref.only_if_active:get() and not is_override then
                    return
                end

                if is_override then
                    r, g, b, a = ref.active_color:get()
                end

                if a <= 0 then
                    return
                end

                local text_size = vector(
                    renderer.measure_text(flags, text)
                )

                position.y = position.y - text_size.y

                renderer.text(
                    position.x,
                    position.y,
                    r, g, b, a,
                    flags, nil, text
                )
            end

            local function update_event_callbacks(value)
                utils.event_callback(
                    'paint_ui',
                    on_paint_ui,
                    value
                )
            end

            local callbacks do
                local function on_enabled(item)
                    update_event_callbacks(item:get())
                end

                ref.enabled:set_callback(
                    on_enabled, true
                )
            end
        end

        local damage_esp do
            local ref = resource.render.user_interface.damage_esp

            local classic_hitboxes = { 0, 2, 3, 4, 5, 6 }
            local classic_cache = { }
            local classic_last_update = 0

            local function reset_classic_cache()
                for k in pairs(classic_cache) do
                    classic_cache[k] = nil
                end
            end

            local function get_classic_best_damage(me, enemy)
                local eye_x, eye_y, eye_z = client.eye_position()

                if eye_x == nil then
                    return 0
                end

                local best_damage = 0

                for i = 1, #classic_hitboxes do
                    local x, y, z = entity.hitbox_position(enemy, classic_hitboxes[i])

                    if x ~= nil then
                        local _, damage = client.trace_bullet(me, eye_x, eye_y, eye_z, x, y, z)
                        damage = damage or 0

                        if damage > best_damage then
                            best_damage = damage
                        end
                    end
                end

                return math.floor(best_damage + 0.5)
            end

            local function update_classic_cache()
                local now = globals.realtime()

                if now - classic_last_update < 0.12 then
                    return
                end

                classic_last_update = now
                reset_classic_cache()

                local me = entity.get_local_player()

                if me == nil or not entity.is_alive(me) then
                    return
                end

                local enemies = entity.get_players(true)

                for i = 1, #enemies do
                    local enemy = enemies[i]

                    if entity.is_alive(enemy) and not entity.is_dormant(enemy) then
                        local damage = get_classic_best_damage(me, enemy)

                        if damage > 0 then
                            classic_cache[enemy] = {
                                damage = damage,
                                lethal = damage >= (entity.get_prop(enemy, 'm_iHealth') or 100)
                            }
                        end
                    end
                end
            end

            local function has_selection(list, value)
                if type(list) ~= 'table' then
                    return false
                end

                for i = 1, #list do
                    if list[i] == value then
                        return true
                    end
                end

                return false
            end

            local function selected_hitbox_multiplier()
                local value = ref.hitbox:get()

                if value == 'Stomach' then
                    return 1.25
                end

                if value == 'Chest' then
                    return 1.0
                end

                if value == 'Leg/feets' then
                    return 0.75
                end

                return 1.0
            end

            local function selected_hitbox_alpha()
                local selected = ref.mark_on:get()

                return has_selection(selected, 'Head') and 255 or 0,
                    has_selection(selected, 'Chest') and 255 or 0,
                    has_selection(selected, 'Stomach') and 255 or 0,
                    has_selection(selected, 'Leg/feets') and 255 or 0
            end

            local function screen_hitbox(player, hitbox)
                local x, y, z = entity.hitbox_position(player, hitbox)

                if x == nil then
                    return nil, nil
                end

                return renderer.world_to_screen(x, y, z)
            end

            local function get_weapon_damage(me, enemy)
                local weapon_ent = entity.get_player_weapon(me)

                if weapon_ent == nil then
                    return nil
                end

                local weapon_idx = entity.get_prop(weapon_ent, 'm_iItemDefinitionIndex')
                if weapon_idx == nil then
                    return nil
                end

                weapon_idx = bit.band(weapon_idx, 65535)

                local weapon = csgo_weapons[weapon_idx]
                if weapon == nil or weapon.damage == nil or weapon.range_modifier == nil or weapon.armor_ratio == nil then
                    return nil
                end

                local lx, ly, lz = entity.get_prop(me, 'm_vecAbsOrigin')
                local ex, ey, ez = entity.get_prop(enemy, 'm_vecOrigin')

                if lx == nil or ex == nil then
                    return nil
                end

                local dx, dy, dz = lx - ex, ly - ey, lz - ez
                local distance = math.sqrt(dx * dx + dy * dy + dz * dz)
                local damage_after_range = weapon.damage * math.pow(weapon.range_modifier, distance * 0.002)
                local armor = entity.get_prop(enemy, 'm_ArmorValue') or 0
                local new_damage = damage_after_range * (weapon.armor_ratio * 0.5)

                if damage_after_range - (damage_after_range * (weapon.armor_ratio * 0.5)) * 0.5 > armor then
                    new_damage = damage_after_range - (armor / 0.5)
                end

                return new_damage
            end

            local font_flags = {
                ['Default'] = 'c',
                ['Small'] = 'c-',
                ['Bold'] = 'cb'
            }

            local function draw_hitbox_mark(x, y, alpha, lethal)
                if x == nil or y == nil or alpha <= 0 then
                    return
                end

                renderer.text(x, y, 253, 69, 106, alpha, 'cbd', 0, lethal and '+' or ' ')
            end

            local function draw_classic_damage(x, y, damage, lethal, alpha_multiplier)
                local normal_r, normal_g, normal_b, normal_a = ref.inactive_color:get()
                local lethal_r, lethal_g, lethal_b, lethal_a = ref.active_color:get()
                local r, g, b, a = normal_r, normal_g, normal_b, normal_a
                local text = string.format('- %d -', damage)

                if lethal then
                    r, g, b, a = lethal_r, lethal_g, lethal_b, lethal_a
                    text = tostring(damage)
                end

                local flags = font_flags[ref.font:get()] or 'c'
                local draw_alpha = a * alpha_multiplier

                renderer.text(x + 1, y + 1, 0, 0, 0, 160 * alpha_multiplier, flags, 0, text)
                renderer.text(x, y, r, g, b, draw_alpha, flags, 0, text)
            end

            local function on_paint()
                local me = entity.get_local_player()

                if me == nil or not entity.is_alive(me) then
                    return
                end

                local enemies = entity.get_players(true)
                local is_solus_style = ref.style:get() == 'Solus'

                if not is_solus_style then
                    update_classic_cache()

                    for enemy, data in pairs(classic_cache) do
                        if entity.is_alive(enemy) and not entity.is_dormant(enemy) then
                            local x1, y1, x2, _, bbox_alpha = entity.get_bounding_box(enemy)

                            if x1 ~= nil and bbox_alpha ~= nil and bbox_alpha > 0 then
                                local alpha_multiplier = bbox_alpha <= 1 and bbox_alpha or utils.clamp(bbox_alpha, 0, 255) / 255
                                local x = x1 + (x2 - x1) * 0.5
                                local y = y1 - ref.offset:get()

                                draw_classic_damage(x, y, data.damage or 0, data.lethal, alpha_multiplier)
                            end
                        end
                    end

                    return
                end

                local alpha = { selected_hitbox_alpha() }
                local enemy_target_idx = client.current_threat()

                for i = 1, #enemies do
                    local enemy = enemies[i]

                    if entity.is_alive(enemy) and not entity.is_dormant(enemy) then
                        local base_damage = get_weapon_damage(me, enemy)

                        if base_damage == nil then
                            goto continue
                        end

                        local display_damage = base_damage * selected_hitbox_multiplier()
                        local enemy_health = entity.get_prop(enemy, 'm_iHealth') or 100

                        local is_damage_lethal = display_damage >= enemy_health
                        local is_lethal_stomach = base_damage * 1.25 >= enemy_health
                        local is_lethal_chest = base_damage >= enemy_health
                        local is_lethal_head = base_damage * 4 >= enemy_health
                        local is_lethal_pelvis = base_damage * 0.75 >= enemy_health

                        local stomach_x, stomach_y = screen_hitbox(enemy, 3)
                        local chest_x, chest_y = screen_hitbox(enemy, 5)
                        local head_x, head_y = screen_hitbox(enemy, 0)
                        local pelvis_x, pelvis_y = screen_hitbox(enemy, 8)
                        local leg_x, leg_y = screen_hitbox(enemy, 7)

                        local x1, y1, x2, _, mult = entity.get_bounding_box(enemy)

                        if x1 ~= nil and mult ~= nil and mult > 0 then
                            local x = x1 + ((x2 - x1) / 2)
                            local y = y1 - (is_solus_style and 17 or ref.offset:get())

                            if is_solus_style then
                                local text_r = is_damage_lethal and 253 or 255
                                local text_g = is_damage_lethal and 69 or 255
                                local text_b = is_damage_lethal and 106 or 255

                                renderer.text(x, y, text_r, text_g, text_b, 255, 'cb', 0, math.floor(display_damage))

                                draw_hitbox_mark(pelvis_x, pelvis_y, alpha[4], is_lethal_pelvis)
                                draw_hitbox_mark(leg_x, leg_y, alpha[4], is_lethal_pelvis)
                                draw_hitbox_mark(stomach_x, stomach_y, alpha[3], is_lethal_stomach)
                                draw_hitbox_mark(chest_x, chest_y, alpha[2], is_lethal_chest)
                                draw_hitbox_mark(head_x, head_y, alpha[1], is_lethal_head)

                                if enemy == enemy_target_idx then
                                    renderer.text(x + 12, y, 255, 255, 255, 255, 'cbd', 0, '-')
                                    renderer.text(x - 12, y, 255, 255, 255, 255, 'cbd', 0, '-')
                                end
                            end
                        end
                    end

                    ::continue::
                end
            end

            local function update_event_callbacks(value)
                if not value then
                    reset_classic_cache()
                end

                utils.event_callback('paint', on_paint, value)
            end

            local callbacks do
                local function on_enabled(item)
                    update_event_callbacks(item:get())
                end

                ref.enabled:set_callback(on_enabled, true)
            end
        end
        local lethal_warnings do
            local ref = resource.render.user_interface.lethal_warnings
            local grenade_cache = { }
            local callbacks_active = false
            local taser_icon = renderer.load_svg('<svg id="svg" version="1.1" width="608" height="689" xmlns="http://www.w3.org/2000/svg"><g id="svgg"><path id="path0" d="M185.803 18.945 C 184.779 19.092,182.028 23.306,174.851 35.722 C 169.580 44.841,157.064 66.513,147.038 83.882 C 109.237 149.365,100.864 163.863,93.085 177.303 C 88.686 184.901,78.772 202.072,71.053 215.461 C 63.333 228.849,53.959 245.069,50.219 251.505 C 46.480 257.941,43.421 263.491,43.421 263.837 C 43.421 264.234,69.566 264.530,114.025 264.635 L 184.628 264.803 181.217 278.618 C 179.342 286.217,174.952 304.128,171.463 318.421 C 167.974 332.714,160.115 364.836,153.999 389.803 C 147.882 414.770,142.934 435.254,143.002 435.324 C 143.127 435.452,148.286 428.934,199.343 364.145 C 215.026 344.243,230.900 324.112,234.619 319.408 C 238.337 314.704,254.449 294.276,270.423 274.013 C 286.397 253.750,303.090 232.582,307.519 226.974 C 340.870 184.745,355.263 166.399,355.263 166.117 C 355.263 165.937,323.554 165.789,284.798 165.789 C 223.368 165.789,214.380 165.667,214.701 164.831 C 215.039 163.949,222.249 151.366,243.554 114.474 C 280.604 50.317,298.192 19.768,298.267 19.444 C 298.355 19.064,188.388 18.576,185.803 18.945" stroke="none" fill="#ffffff" fill-rule="evenodd"></path></g></svg>', 150, 150)

            local grenade_weapons = {
                weapon_hegrenade = true,
                weapon_smokegrenade = true,
                weapon_molotov = true,
