            }

            local grenade_order = {
                weapon_hegrenade = 1,
                weapon_molotov = 2,
                weapon_incgrenade = 2,
                weapon_smokegrenade = 3
            }

            local grenade_icons = {
                weapon_hegrenade = images.get_weapon_icon('weapon_hegrenade'),
                weapon_smokegrenade = images.get_weapon_icon('weapon_smokegrenade'),
                weapon_molotov = images.get_weapon_icon('weapon_molotov'),
                weapon_incgrenade = images.get_weapon_icon('weapon_incgrenade')
            }

            local grenade_icon_size = {
                weapon_hegrenade = { 17, 12 },
                weapon_smokegrenade = { 17, 12 },
                weapon_molotov = { 17, 12 },
                weapon_incgrenade = { 17, 12 }
            }

            local function clear_cache()
                grenade_cache = { }
            end

            local function get_weapon_info(weapon)
                if weapon == nil then
                    return nil
                end

                return csgo_weapons(weapon)
            end

            local function get_weapon_index(weapon)
                if weapon == nil then
                    return nil
                end

                local item_definition = entity.get_prop(weapon, 'm_iItemDefinitionIndex')
                if item_definition ~= nil then
                    return bit.band(item_definition, 65535)
                end

                local weapon_info = get_weapon_info(weapon)
                return weapon_info ~= nil and weapon_info.idx or nil
            end

            local function get_weapons(player)
                local result = { }

                for i = 0, 64 do
                    local weapon = entity.get_prop(player, 'm_hMyWeapons', i)

                    if weapon ~= nil then
                        result[#result + 1] = weapon
                    end
                end

                return result
            end

            local function has_weapon_index(player, weapon_index)
                local weapons = get_weapons(player)

                for i = 1, #weapons do
                    if get_weapon_index(weapons[i]) == weapon_index then
                        return true
                    end
                end

                return false
            end

            local function get_origin(player)
                local x, y, z = entity.get_origin(player)

                if x == nil then
                    x, y, z = entity.get_prop(player, 'm_vecOrigin')
                end

                if x == nil then
                    return nil
                end

                return vector(x, y, z)
            end

            local function get_distance(a, b)
                local origin_a = get_origin(a)
                local origin_b = get_origin(b)

                if origin_a == nil or origin_b == nil then
                    return nil
                end

                return (origin_a - origin_b):length()
            end

            local function get_alpha_multiplier(alpha)
                return alpha <= 1 and alpha or utils.clamp(alpha, 0, 255) / 255
            end

            local function get_revolver_lethal_state(attacker, target)
                local weapon = entity.get_player_weapon(attacker)

                if get_weapon_index(weapon) ~= 64 then
                    return 0
                end

                if attacker == entity.get_local_player() then
                    local eye_x, eye_y, eye_z = client.eye_position()
                    if eye_x == nil then
                        return 0
                    end

                    local health = entity.get_prop(target, 'm_iHealth') or 100
                    local best_damage = 0
                    local hitboxes = { 0, 2, 3, 4, 5, 6 }

                    for i = 1, #hitboxes do
                        local x, y, z = entity.hitbox_position(target, hitboxes[i])

                        if x ~= nil then
                            local _, damage = client.trace_bullet(attacker, eye_x, eye_y, eye_z, x, y, z)
                            best_damage = math.max(best_damage, damage or 0)
                        end
                    end

                    if best_damage >= health then
                        return 2
                    end

                    if best_damage > 0 then
                        return 1
                    end

                    return 0
                end

                if (entity.get_prop(target, 'm_ArmorValue') or 0) > 0 then
                    return 0
                end

                local distance = get_distance(attacker, target)
                if distance == nil then
                    return 0
                end

                if distance < 511 then
                    return 2
                end

                if distance < 585 then
                    return 1
                end

                return 0
            end

            local function get_revolver_text(state, incoming)
                if incoming then
                    return state == 1 and 'R8' or 'R8+'
                end

                return state == 1 and 'DMG' or 'DMG+'
            end

            local function get_revolver_color(state, incoming)
                if incoming then
                    return state == 1 and 255 or 255, state == 1 and 160 or 40, state == 1 and 40 or 55
                end

                return state == 1 and 255 or 50, state == 1 and 0 or 205, state == 1 and 0 or 50
            end

            local function draw_revolver_warning(me, enemy)
                local x1, y1, x2, _, alpha = entity.get_bounding_box(enemy)
                if x1 == nil or alpha == 0 then
                    return
                end

                local alpha_multiplier = get_alpha_multiplier(alpha)
                local local_state = get_revolver_lethal_state(me, enemy)

                if local_state ~= 0 then
                    local text = get_revolver_text(local_state, false)
                    local r, g, b = get_revolver_color(local_state, false)

                    renderer.text((x1 + x2) * 0.5, y1 - 20, r, g, b, 255 * alpha_multiplier, 'cb', 0, text)
                end

                local enemy_state = get_revolver_lethal_state(enemy, me)
                if enemy_state == 0 then
                    return
                end

                do
                    local text = get_revolver_text(enemy_state, true)
                    local r, g, b = get_revolver_color(enemy_state, true)

                    renderer.text((x1 + x2) * 0.5, y1 - 34, r, g, b, 255 * alpha_multiplier, 'cb', 0, text)
                end

                local ex, ey, ez = entity.hitbox_position(enemy, 3)
                local mx, my, mz = entity.hitbox_position(me, 3)
                if ex == nil or mx == nil then
                    return
                end

                local esx, esy = renderer.world_to_screen(ex, ey, ez)
                local msx, msy = renderer.world_to_screen(mx, my, mz)

                if esx ~= nil and msx ~= nil then
                    renderer.line(esx, esy, msx, msy, 255, 0, 0, 180 * alpha_multiplier)
                end
            end

            local function draw_taser_warning(me, enemy)
                if not has_weapon_index(enemy, 31) then
                    return
                end

                local x1, y1, _, _, alpha = entity.get_bounding_box(enemy)
                if x1 == nil or alpha == 0 then
                    return
                end

                local alpha_multiplier = get_alpha_multiplier(alpha)
                local mode = ref.taser:get()
                if mode == 'Off' then
                    return
                end

                local col = color(ref.taser_color:get())

                if get_weapon_index(entity.get_player_weapon(enemy)) == 31 then
                    col = color(ref.taser_active_color:get())
                end

                local distance = get_distance(me, enemy)

                if distance ~= nil and distance < 190 then
                    col = color(ref.taser_range_color:get())
                end

                local text = mode == 'Text' and 'ZEUS' or 'Z'
                if mode == 'Icon' and taser_icon ~= nil then
                    renderer.texture(taser_icon, x1 - 12, y1, 20, 20, col.r, col.g, col.b, col.a * alpha_multiplier, 'f')
                    return
                end

                renderer.text(x1 - 10, y1, col.r, col.g, col.b, col.a * alpha_multiplier, 'c', 0, text)
            end

            local function get_grenade_inventory(player)
                local inventory = { }
                local weapons = get_weapons(player)

                for i = 1, #weapons do
                    local weapon_info = get_weapon_info(weapons[i])
                    local console_name = weapon_info ~= nil and weapon_info.console_name or nil

                    if console_name ~= nil and grenade_weapons[console_name] then
                        inventory[#inventory + 1] = console_name
                    end
                end

                return inventory
            end

            local function cache_player_grenades(player)
                if not entity.is_dormant(player) then
                    grenade_cache[player] = get_grenade_inventory(player)
                end

                if grenade_cache[player] == nil then
                    grenade_cache[player] = { }
                end

                return grenade_cache[player]
            end

            local function should_draw_player(me, player, spectating_enemy)
                if player == me then
                    return false
                end

                if spectating_enemy then
                    return not entity.is_enemy(player)
                end

                return entity.is_enemy(player)
            end

            local function draw_grenade_inventory(me)
                if not ref.nade_inventory:get() then
                    return
                end

                local observer_mode = entity.get_prop(me, 'm_iObserverMode')
                local observer_target = entity.get_prop(me, 'm_hObserverTarget')
                local spectating_enemy = (
                    not entity.is_alive(me) and
                    (observer_mode == 4 or observer_mode == 5) and
                    observer_target ~= nil and
                    entity.is_enemy(observer_target)
                )

                local base_color = color(ref.nade_color:get())
                local y_offset = ref.nade_offset:get()

                for player = 1, globals.maxplayers() do
                    local connected = entity.get_prop(entity.get_player_resource(), 'm_bConnected', player) == 1

                    if connected and should_draw_player(me, player, spectating_enemy) and entity.is_alive(player) then
                        local inventory = cache_player_grenades(player)

                        if #inventory > 0 then
                            table.sort(inventory, function(a, b)
                                return (grenade_order[a] or 0) < (grenade_order[b] or 0)
                            end)

                            local x1, y1, x2, _, alpha = entity.get_bounding_box(player)

                            if x1 ~= nil and alpha ~= 0 then
                                local alpha_multiplier = get_alpha_multiplier(alpha)
                                local total_width = 0

                                for i = 1, #inventory do
                                    local size = grenade_icon_size[inventory[i]]
                                    if size ~= nil then
                                        total_width = total_width + size[1]

                                        if i ~= #inventory then
                                            total_width = total_width + 4
                                        end
                                    end
                                end

                                local draw_x = (x1 + x2) * 0.5 - total_width * 0.5
                                local draw_y = y1 - 16 - y_offset
                                local r, g, b = base_color.r, base_color.g, base_color.b
                                local a = base_color.a * alpha_multiplier

                                if entity.is_dormant(player) then
                                    local gray = round((r + g + b) / 3) * 0.75
                                    r, g, b = gray, gray, gray
                                end

                                for i = 1, #inventory do
                                    local name = inventory[i]
                                    local icon = grenade_icons[name]
                                    local size = grenade_icon_size[name]

                                    if icon ~= nil and size ~= nil then
                                        icon:draw(round(draw_x), round(draw_y), size[1], size[2], r, g, b, a)
                                        draw_x = draw_x + size[1] + 4
                                    end
                                end
                            end
                        end
                    end
                end
            end

            local function on_item_remove(e)
                local player = client.userid_to_entindex(e.userid)
                if player == nil or not entity.is_enemy(player) then
                    return
                end

                local item = 'weapon_' .. e.item
                if not grenade_weapons[item] then
                    return
                end

                local inventory = grenade_cache[player] or { }
                local next_inventory = { }
                local removed = false

                for i = 1, #inventory do
                    if inventory[i] == item and not removed then
                        removed = true
                    else
                        next_inventory[#next_inventory + 1] = inventory[i]
                    end
                end

                grenade_cache[player] = next_inventory
            end

            local function on_item_pickup(e)
                local player = client.userid_to_entindex(e.userid)
                if player == nil or not entity.is_enemy(player) then
                    return
                end

                local item = 'weapon_' .. e.item
                if not grenade_weapons[item] then
                    return
                end

                grenade_cache[player] = grenade_cache[player] or { }
                grenade_cache[player][#grenade_cache[player] + 1] = item
            end

            local function on_player_reset(e)
                local player = client.userid_to_entindex(e.userid)
                if player ~= nil then
                    grenade_cache[player] = { }
                end
            end

            local function on_paint()
                local me = entity.get_local_player()
                if me == nil then
                    return
                end

                local should_draw_revolver = ref.revolver:get()
                local should_draw_taser = ref.taser:get() ~= 'Off'

                if should_draw_revolver or should_draw_taser then
                    local enemies = entity.get_players(true)

                    for i = 1, #enemies do
                        local enemy = enemies[i]

                        if entity.is_alive(enemy) then
                            if should_draw_revolver then
                                draw_revolver_warning(me, enemy)
                            end

                            if should_draw_taser then
                                draw_taser_warning(me, enemy)
                            end
                        end
                    end
                end

                draw_grenade_inventory(me)
            end

            local function any_enabled()
                return ref.revolver:get() or ref.taser:get() ~= 'Off' or ref.nade_inventory:get()
            end

            local function update_event_callbacks()
                local value = any_enabled()

                if value == callbacks_active then
                    return
                end

                callbacks_active = value

                if not value then
                    clear_cache()
                end

                utils.event_callback('paint', on_paint, value)
                utils.event_callback('level_init', clear_cache, value)
                utils.event_callback('player_death', on_player_reset, value)
                utils.event_callback('player_spawn', on_player_reset, value)
                utils.event_callback('item_remove', on_item_remove, value)
                utils.event_callback('item_pickup', on_item_pickup, value)
            end

            local callbacks do
                ref.revolver:set_callback(update_event_callbacks, true)
                ref.taser:set_callback(update_event_callbacks, true)
                ref.nade_inventory:set_callback(update_event_callbacks, true)
            end
        end

        local grenade_indicator do
            local ref = resource.render.user_interface.grenade_indicator
            local cache = { }

            local function clear_cache()
                for k in pairs(cache) do
                    cache[k] = nil
                end
            end

            local function get_entities(classname)
                local ok, ents = pcall(entity.get_all, classname)

                if ok and ents ~= nil then
                    return ents
                end

                return { }
            end

            local function get_origin_safe(ent)
                local x, y, z = entity.get_origin(ent)

                if x == nil then
                    x, y, z = entity.get_prop(ent, 'm_vecOrigin')
                end

                if x == nil then
                    return nil
                end

                return vector(x, y, z)
            end

            local function get_tick_prop(ent, props)
                for i = 1, #props do
                    local ok, value = pcall(entity.get_prop, ent, props[i])

                    if ok and value ~= nil and value > 0 then
                        return value
                    end
                end

                return nil
            end

            local function ease_out_cubic(x)
                x = utils.clamp(x or 0, 0, 1)

                return 1 - math.pow(1 - x, 3)
            end

            local function circle_3d(pos, radius, start_at, percentage, segment, filled, r, g, b, a)
                local old_x, old_y
                local end_at = start_at + math.floor((percentage or 1) * 360)
                local segments = math.max(12, segment or 64)
                local step = math.max(1, (end_at - start_at) / segments)

                for rot = start_at, end_at, step do
                    local rad = math.rad(rot)
                    local px = radius * math.cos(rad) + pos.x
                    local py = radius * math.sin(rad) + pos.y
                    local sx, sy = renderer.world_to_screen(px, py, pos.z)
                    local cx, cy = renderer.world_to_screen(pos.x, pos.y, pos.z)

                    if sx ~= nil and sy ~= nil and old_x ~= nil and old_y ~= nil then
                        if filled and cx ~= nil and cy ~= nil then
                            renderer.triangle(sx, sy, old_x, old_y, cx, cy, r, g, b, a)
                        else
                            renderer.line(sx, sy, old_x, old_y, r, g, b, a)
                        end
                    end

                    old_x, old_y = sx, sy
                end
            end

            local function get_grenade_data(ent, kind)
                local data = cache[ent]
                local duration = kind == 'smoke' and 18.0 or 7.1
                local tick_props = kind == 'smoke'
                    and { 'm_nSmokeEffectTickBegin' }
                    or { 'm_nFireEffectTickBegin' }
                local tick_begin = get_tick_prop(ent, tick_props)
                local start_time = tick_begin ~= nil and tick_begin * globals.tickinterval() or nil

                if data == nil then
                    data = {
                        kind = kind,
                        start = start_time or globals.curtime(),
                        origin = get_origin_safe(ent)
                    }

                    cache[ent] = data
                end

                if start_time ~= nil then
                    data.start = start_time
                end

                local origin = get_origin_safe(ent)

                if origin ~= nil then
                    data.origin = origin
                end

                if data.origin == nil then
                    return nil
                end

                local elapsed = globals.curtime() - data.start

                if elapsed < 0 then
                    elapsed = 0
                end

                local remaining = duration - elapsed

                if remaining <= -1 then
                    return nil
                end

                local reveal_time = kind == 'smoke' and 1.65 or 0.85

                return {
                    origin = data.origin,
                    duration = duration,
                    remaining = utils.clamp(remaining, 0, duration),
                    progress = utils.clamp(remaining / duration, 0, 1),
                    life_progress = utils.clamp(elapsed / duration, 0, 1),
                    reveal_progress = utils.clamp(elapsed / reveal_time, 0, 1),
                    elapsed = elapsed,
                    kind = kind
                }
            end

            local function draw_timer_card(pos, kind, remaining, color)
                local sx, sy = renderer.world_to_screen(pos.x, pos.y, pos.z + 34)

                if sx == nil or sy == nil then
                    return
                end

                local r, g, b = color[1], color[2], color[3]
                local style = ref.style:get()
                local label = kind == 'smoke' and 'smoke' or 'molotov'
                local text = style == 'Minimal text'
                    and string.format('%.1fs', math.max(0, remaining))
                    or string.format('%s %.1fs', label, math.max(0, remaining))

                renderer.text(sx + 1, sy + 1, 0, 0, 0, 180, 'c', 0, text)
                renderer.text(sx, sy, r, g, b, 235, 'c', 0, text)
            end

            local function draw_smoke_reveal(data, color, now)
                local reveal_done = data.reveal_progress >= 1
                local reveal = reveal_done and 1 or ease_out_cubic(data.reveal_progress)
                local radius = 144 * reveal
                local breathe = reveal_done and 0 or math.sin(now * 2.15 + data.elapsed) * 2.5
                local r, g, b = color[1], color[2], color[3]
                local style = ref.style:get()

                if style == 'Minimal text' or radius < 6 then
                    return
                end

                local alpha = reveal_done and 92 or (45 + reveal * 65)

                if style == 'Soft glow' then
                    alpha = alpha * 0.72
                end

                if not ref.outline_only:get() then
                    circle_3d(data.origin, radius, 0, 1, 96, true, r, g, b, style == 'Soft glow' and 8 + 12 * reveal or 12 + 18 * reveal)
                end

                circle_3d(data.origin, radius + breathe, 0, 1, 96, false, r, g, b, alpha)
            end

            local draw_molotov_ignite

            local function get_prop_array(ent, prop, max_count)
                local ok, first = pcall(entity.get_prop, ent, prop)
                local values = { }

                if ok and first ~= nil then
                    local prop_values = { pcall(entity.get_prop, ent, prop) }

                    if prop_values[1] then
                        for i = 2, #prop_values do
                            values[#values + 1] = prop_values[i]
                        end
                    end
                end

                if #values == 0 then
                    for i = 0, max_count - 1 do
                        local ok_index, value = pcall(entity.get_prop, ent, prop, i)
                        values[#values + 1] = ok_index and value or nil
                    end
                end

                return values
            end

            local function convex_hull(points)
                if #points <= 3 then
                    return points
                end

                table.sort(points, function(a, b)
                    return a.x == b.x and a.y < b.y or a.x < b.x
                end)

                local function cross(o, a, b)
                    return (a.x - o.x) * (b.y - o.y) - (a.y - o.y) * (b.x - o.x)
                end

                local lower = { }
                for i = 1, #points do
                    while #lower >= 2 and cross(lower[#lower - 1], lower[#lower], points[i]) <= 0 do
                        lower[#lower] = nil
                    end

                    lower[#lower + 1] = points[i]
                end

                local upper = { }
                for i = #points, 1, -1 do
                    while #upper >= 2 and cross(upper[#upper - 1], upper[#upper], points[i]) <= 0 do
                        upper[#upper] = nil
                    end

                    upper[#upper + 1] = points[i]
                end

                lower[#lower] = nil
                upper[#upper] = nil

                for i = 1, #upper do
                    lower[#lower + 1] = upper[i]
                end

                return lower
            end

            local function smooth_screen_polygon(points, passes)
                for _ = 1, passes do
                    local smoothed = { }

                    for i = 1, #points do
                        local current = points[i]
                        local next_point = points[i % #points + 1]

                        smoothed[#smoothed + 1] = {
                            x = current.x * 0.75 + next_point.x * 0.25,
                            y = current.y * 0.75 + next_point.y * 0.25
                        }
                        smoothed[#smoothed + 1] = {
                            x = current.x * 0.25 + next_point.x * 0.75,
                            y = current.y * 0.25 + next_point.y * 0.75
                        }
                    end

                    points = smoothed
                end

                return points
            end

            local function draw_molotov_alternative(ent, data, color, now)
                local style = ref.style:get()

                if style == 'Minimal text' then
                    return
                end

                local origin = data.origin
                local x_delta = get_prop_array(ent, 'm_fireXDelta', 64)
                local y_delta = get_prop_array(ent, 'm_fireYDelta', 64)
                local z_delta = get_prop_array(ent, 'm_fireZDelta', 64)
                local burning = get_prop_array(ent, 'm_bFireIsBurning', 64)
                local points = { }
                local spread = 58
                local samples = 10

                for i = 1, math.max(#x_delta, #y_delta, #burning) do
                    local active = burning[i]

                    if active == true or active == 1 or active == nil then
                        local x = x_delta[i] or 0
                        local y = y_delta[i] or 0
                        local z = z_delta[i] or 0

                        for sample = 1, samples do
                            local angle = (sample / samples) * math.pi * 2

                            points[#points + 1] = {
                                x = origin.x + x + math.cos(angle) * spread,
                                y = origin.y + y + math.sin(angle) * spread,
                                z = origin.z + z
                            }
                        end
                    end
                end

                if #points < 3 then
                    draw_molotov_ignite(data, color, now)
                    return
                end

                local hull = convex_hull(points)
                local screen = { }
                local cx, cy = 0, 0

                for i = 1, #hull do
                    local sx, sy = renderer.world_to_screen(hull[i].x, hull[i].y, hull[i].z)

                    if sx ~= nil and sy ~= nil then
                        screen[#screen + 1] = { x = sx, y = sy }
                        cx, cy = cx + sx, cy + sy
                    end
                end

                if #screen < 3 then
                    draw_molotov_ignite(data, color, now)
                    return
                end

                screen = smooth_screen_polygon(screen, 2)
                cx, cy = 0, 0

                for i = 1, #screen do
                    cx, cy = cx + screen[i].x, cy + screen[i].y
                end

                cx, cy = cx / #screen, cy / #screen

                local reveal = ease_out_cubic(data.reveal_progress)
                local pulse = math.sin(now * 7.5 + data.elapsed * 2.0) * 12
                local r, g, b = color[1], color[2], color[3]
                local fill_alpha = 16 + 20 * reveal
                local line_alpha = 82 + 42 * reveal + pulse

                if style == 'Soft glow' then
                    fill_alpha = fill_alpha * 0.72
                    line_alpha = line_alpha * 0.78
                end

                for i = 1, #screen do
                    local next_point = screen[i % #screen + 1]
                    if not ref.outline_only:get() then
                        pcall(renderer.triangle, cx, cy, screen[i].x, screen[i].y, next_point.x, next_point.y, r, g, b, fill_alpha)
                    end

                    renderer.line(screen[i].x, screen[i].y, next_point.x, next_point.y, r, g, b, line_alpha)
                end
            end

            draw_molotov_ignite = function(data, color, now)
                local reveal_done = data.reveal_progress >= 1
                local reveal = reveal_done and 1 or ease_out_cubic(data.reveal_progress)
                local radius = 150 * reveal
                local flicker = reveal_done and 0 or math.sin(now * 8.5 + data.elapsed * 3.0) * 4
                local r, g, b = color[1], color[2], color[3]
                local style = ref.style:get()

                if style == 'Minimal text' or radius < 6 then
                    return
                end

                local alpha = reveal_done and 110 or (55 + reveal * 70)

                if style == 'Soft glow' then
                    alpha = alpha * 0.72
                end

                if not ref.outline_only:get() then
                    circle_3d(data.origin, radius, 0, 1, 96, true, r, g, b, style == 'Soft glow' and 9 + 13 * reveal or 14 + 20 * reveal)
                end

                circle_3d(data.origin, radius + flicker, 0, 1, 96, false, r, g, b, alpha)
            end

            local function on_paint()
                if not ref.timer:get() and not ref.radius:get() then
                    return
                end

                local now = globals.realtime()
                local sr, sg, sb, sa = ref.smoke_color:get()
                local mr, mg, mb, ma = ref.molotov_color:get()
                local smoke_color = { sr, sg, sb, sa }
                local molotov_color = { mr, mg, mb, ma }
                local seen = { }

                for _, ent in ipairs(get_entities('CSmokeGrenadeProjectile')) do
                    local did_smoke = entity.get_prop(ent, 'm_bDidSmokeEffect')

                    if did_smoke == nil or did_smoke == 1 then
                        local data = get_grenade_data(ent, 'smoke')

                        if data ~= nil and data.remaining > 0 then
                            seen[ent] = true

                            if ref.radius:get() then
                                draw_smoke_reveal(data, smoke_color, now)
                            end

                            if ref.timer:get() then
                                draw_timer_card(data.origin, 'smoke', data.remaining, smoke_color)
                            end
                        end
                    end
                end

                for _, ent in ipairs(get_entities('CInferno')) do
                    local data = get_grenade_data(ent, 'molotov')

                    if data ~= nil and data.remaining > 0 then
                        seen[ent] = true

                        if ref.radius:get() then
                            if ref.style:get() == 'Alternative' then
                                draw_molotov_alternative(ent, data, molotov_color, now)
                            else
                                draw_molotov_ignite(data, molotov_color, now)
                            end
                        end

                        if ref.timer:get() then
                            draw_timer_card(data.origin, 'molotov', data.remaining, molotov_color)
                        end
                    end
                end

                for ent in pairs(cache) do
                    if seen[ent] ~= true then
                        local data = cache[ent]

                        if data == nil or globals.curtime() - data.start > 20 then
                            cache[ent] = nil
                        end
                    end
                end
            end

            local function update_event_callbacks(value)
                if not value then
                    clear_cache()
                end

                utils.event_callback('paint', on_paint, value)
                utils.event_callback('round_start', clear_cache, value)
            end

            local callbacks do
                local function on_enabled(item)
                    update_event_callbacks(item:get())
                end

                ref.enabled:set_callback(on_enabled, true)
            end
        end

        local grenade_trail do
            local ref = resource.render.user_interface.grenade_trail
            local standard_grenades_ref = ui.reference('Visuals', 'Other ESP', 'Grenades')

            local histories = { }
            local classes = {
                'CBaseCSGrenadeProjectile',
                'CSmokeGrenadeProjectile',
                'CMolotovProjectile',
                'CIncendiaryGrenadeProjectile',
                'CDecoyProjectile'
            }

            local function clear_histories()
                for k in pairs(histories) do
                    histories[k] = nil
                end
            end

            local function draw_enhanced_line(x1, y1, x2, y2, r, g, b, a, thickness, glow)
                if a <= 0 then
                    return
                end

                local final_alpha = a

                if thickness == 0 then
                    final_alpha = a * 0.4
                    renderer.line(x1, y1, x2, y2, r, g, b, final_alpha)
                else
                    for i = 0, thickness - 1 do
                        renderer.line(x1 + i, y1, x2 + i, y2, r, g, b, a)
                    end
                end

                if glow <= 0 then
                    return
                end

                for i = 1, glow do
                    local glow_alpha = math.floor(final_alpha * (1 - (i / glow) ^ 0.6) * 0.15)

                    if glow_alpha > 0 then
                        renderer.line(x1, y1 - i, x2, y2 - i, r, g, b, glow_alpha)
                        renderer.line(x1, y1 + i, x2, y2 + i, r, g, b, glow_alpha)
                        renderer.line(x1 - i, y1, x2 - i, y2, r, g, b, glow_alpha)
                        renderer.line(x1 + i, y1, x2 + i, y2, r, g, b, glow_alpha)
                    end
                end
            end

            local function collect_active_grenades()
                local active = { }

                for i = 1, #classes do
                    local found = entity.get_all(classes[i])

                    if found ~= nil then
                        for j = 1, #found do
                            active[found[j]] = true
                        end
                    end
                end

                return active
            end

            local function on_paint()
                local r, g, b, base_alpha = ref.color:get()
                local thickness = ref.thickness:get()
                local glow = ref.glow:get()
                local max_lifetime = ref.fade:get() / 10
                local now = globals.curtime()
                local active = collect_active_grenades()

                for ent, path in pairs(histories) do
                    if active[ent] then
                        local x, y, z = entity.get_prop(ent, 'm_vecOrigin')

                        if x ~= nil then
                            path[#path + 1] = {
                                x = x,
                                y = y,
                                z = z,
                                time = now
                            }
                        end
                    end

                    if #path > 1 then
                        for i = #path, 2, -1 do
                            local p1 = path[i - 1]
                            local p2 = path[i]
                            local age = now - p1.time
                            local time_factor = 1 - (age / max_lifetime)

                            if time_factor > 0 then
                                local alpha = math.floor(base_alpha * time_factor)
                                local sx1, sy1 = renderer.world_to_screen(p1.x, p1.y, p1.z)
                                local sx2, sy2 = renderer.world_to_screen(p2.x, p2.y, p2.z)

                                if sx1 ~= nil and sx2 ~= nil then
                                    draw_enhanced_line(sx1, sy1, sx2, sy2, r, g, b, alpha, thickness, glow)
                                end
                            else
                                table.remove(path, i - 1)
                            end
                        end
                    end

                    if not active[ent] and #path <= 1 then
                        histories[ent] = nil
                    end
                end

                for ent in pairs(active) do
                    histories[ent] = histories[ent] or { }
                end
            end

            local function update_standard_grenades(value)
                if value then
                    override.set(standard_grenades_ref, false)
                else
                    override.unset(standard_grenades_ref)
                end
            end

            local function on_shutdown()
                override.unset(standard_grenades_ref)
            end

            local function update_event_callbacks(value)
                if not value then
                    clear_histories()
                end

                update_standard_grenades(value)
                utils.event_callback('paint', on_paint, value)
                utils.event_callback('round_start', clear_histories, value)
                utils.event_callback('shutdown', on_shutdown, value)
            end

            local callbacks do
                local function on_enabled(item)
                    update_event_callbacks(item:get())
                end

                ref.enabled:set_callback(on_enabled, true)
            end
        end
    end

    local hit_markers do
        local damage_marker do
            local ref = resource.render.hit_markers.damage_marker

            local STATE_BODY = 0
            local STATE_HEAD = 1
            local STATE_MISMATCH = 2

            local list = { }
            local damages = { }

            local font_map = {
                ['Default'] = '',
                ['Bold'] = 'b'
            }

            local function get_id(id)
                return (id % 15) + 1
            end

            local function reset_data()
                for i = 1, #list do
                    list[i] = nil
                end
            end

            local function get_color(state)
                if state == STATE_BODY then
                    return color(ref.body_color:get())
                end

                if state == STATE_HEAD then
                    return color(ref.head_color:get())
                end

                if state == STATE_MISMATCH then
                    return color(ref.mismatch_color:get())
                end

                return color(255, 255, 255, 255)
            end

            local function on_aim_fire(e)
                damages[get_id(e.id)] = e.damage
            end

            local function on_aim_hit(e)
                local data = list[#list]

                if data == nil then
                    return
                end

                local aim_damage = damages[get_id(e.id)]

                if aim_damage == nil then
                    return
                end

                if data.damage < aim_damage then
                    data.state = STATE_MISMATCH
                end
            end

            local function on_player_hurt(e)
                local me = entity.get_local_player()

                local userid = client.userid_to_entindex(e.userid)
                local attacker = client.userid_to_entindex(e.attacker)

                if userid == me or attacker ~= me then
                    return
                end

                local pos = vector(utils.get_eye_position(userid))

                local state = e.hitgroup == 1
                    and STATE_HEAD or STATE_BODY

                local duration = ref.duration:get()

                local damage = e.dmg_health
                local remaining = globals.realtime() + duration

                table.insert(list, {
                    pos = pos,
                    state = state,
                    damage = damage,
                    remaining = remaining
                })
            end

            local function on_paint()
                local dt = globals.frametime()
                local time = globals.realtime()

                local font = ref.font:get()
                local speed = ref.speed:get()

                local flags = font_map[font]

                if flags == nil then
                    flags = ''
                end

                flags = flags .. 'c'

                for i = #list, 1, -1 do
                    local data = list[i]

                    if time > data.remaining then
                        table.remove(list, i)
                        goto continue
                    end

                    data.pos.z = data.pos.z + speed * dt
                    ::continue::
                end

                for i = 1, #list do
                    local data = list[i]

                    local alpha = 1.0

                    local text = data.damage
                    local state = data.state

                    local col = get_color(state)

                    local liferemaining = data.remaining - time

                    if liferemaining < 0.7 then
                        alpha = liferemaining / 0.7
                    end

                    local x, y = renderer.world_to_screen(data.pos:unpack())

                    if x == nil or y == nil then
                        goto continue
                    end

                    col = col:clone()
                    col.a = col.a * alpha

                    renderer.text(x, y, col.r, col.g, col.b, col.a, flags, nil, text)
                    ::continue::
                end
            end

            local function update_event_callbacks(value)
                if not value then
                    reset_data()
                end

                utils.event_callback(
                    'aim_fire',
                    on_aim_fire,
                    value
                )

                utils.event_callback(
                    'aim_hit',
                    on_aim_hit,
                    value
                )

                utils.event_callback(
                    'player_hurt',
                    on_player_hurt,
                    value
                )

                utils.event_callback(
                    'paint',
                    on_paint,
                    value
                )
            end

            local callbacks do
                local function on_enabled(item)
                    update_event_callbacks(item:get())
                end

                ref.enabled:set_callback(
                    on_enabled, true
                )
            end
        end

        local screen_marker do
            local ref = resource.render.hit_markers.screen_marker

            local hurt_time = 0.0

            local function reset_data()
                hurt_time = 0.0
            end

            local function on_player_hurt(e)
                local me = entity.get_local_player()

                local userid = client.userid_to_entindex(e.userid)
                local attacker = client.userid_to_entindex(e.attacker)

                if userid == me or attacker ~= me then
                    return
                end

                hurt_time = 0.5
            end

            local function on_paint()
                local alpha = 1.0

                if hurt_time < 0.25 then
                    alpha = hurt_time / 0.25
                end

                local center = 0.5 * vector(
                    client.screen_size()
                )

                local col = color(ref.color:get())

                col.a = col.a * alpha

                renderer.line(center.x - 10, center.y - 10, center.x - 5, center.y - 5, col:unpack())
                renderer.line(center.x + 10, center.y - 10, center.x + 5, center.y - 5, col:unpack())
                renderer.line(center.x + 10, center.y + 10, center.x + 5, center.y + 5, col:unpack())
                renderer.line(center.x - 10, center.y + 10, center.x - 5, center.y + 5, col:unpack())

                hurt_time = math.max(hurt_time - globals.frametime(), 0.0)
            end

            local function update_event_callbacks(value)
                if not value then
                    reset_data()
                end

                utils.event_callback(
                    'player_hurt',
                    on_player_hurt,
                    value
                )

                utils.event_callback(
                    'paint',
                    on_paint,
                    value
                )
            end

            local callbacks do
                local function on_enabled(item)
                    update_event_callbacks(item:get())
                end

                ref.enabled:set_callback(
                    on_enabled, true
                )
            end
        end

        local world_marker do
            local ref = resource.render.hit_markers.world_marker

            local list = { }
            local coords = { }

            local function get_id(id)
                return (id % 15) + 1
            end

            local function clear_list()
                for i = 1, #list do
                    list[i] = nil
                end
            end

            local function on_aim_fire(e)
                coords[get_id(e.id)] = vector(e.x, e.y, e.z)
            end

            local function on_aim_hit(e)
                local time = globals.realtime() + ref.duration:get()
                local point = coords[get_id(e.id)]

                if point == nil then
                    return
                end

                table.insert(list, {
                    time = time,
                    point = point
                })
            end

            local function on_paint()
                local time = globals.realtime()

                for i = #list, 1, -1 do
                    local data = list[i]

                    if time > data.time then
                        table.remove(list, i)
                    end
                end

                for i = 1, #list do
                    local data = list[i]

                    local alpha = 1.0

                    local liferemaining = data.time - time

                    if liferemaining < 0.7 then
                        alpha = liferemaining / 0.7
                    end

                    local x, y = renderer.world_to_screen(
                        data.point:unpack()
                    )

                    if x == nil or y == nil then
                        goto continue
                    end

                    local thickness = ref.thickness:get() * 0.5
                    local size = ref.size:get() + thickness

                    local color_h = color(ref.horizontal_color:get())
                    local color_v = color(ref.vertical_color:get())

                    color_h.a = color_h.a * alpha
                    color_v.a = color_v.a * alpha

                    renderer.rectangle(x - size, y - thickness, size * 2, thickness * 2, color_h:unpack())
                    renderer.rectangle(x - thickness, y - size, thickness * 2, size * 2, color_v:unpack())

                    ::continue::
                end
            end

            local function update_event_callbacks(value)
                if not value then
                    clear_list()
                end

                utils.event_callback(
                    'aim_fire',
                    on_aim_fire,
                    value
                )

                utils.event_callback(
                    'aim_hit',
                    on_aim_hit,
                    value
                )

                utils.event_callback(
                    'paint',
                    on_paint,
                    value
                )
            end

            local callbacks do
                local function on_enabled(item)
                    update_event_callbacks(item:get())
                end

                ref.enabled:set_callback(
                    on_enabled, true
                )
            end
        end


        local hitsound do
            local ref = resource.render.hit_markers.hitsound

            local playvol = cvar.playvol

            local sounds = {
                ['Switch 3D'] = 'buttons\\light_power_on_switch_01.wav',
                ['Senko'] = 'survival\\paradrop_idle_01.wav',
                ['Menu'] = 'ui\\csgo_ui_contract_type1.wav',
                ['Strain'] = 'physics\\wood\\wood_strain7.wav',
                ['Stop'] = 'doors\\wood_stop1.wav',
                ['Impact'] = 'physics\\wood\\wood_plank_impact_hard4.wav',
                ['Warning'] = 'resource\\warning.wav'
            }

            local ref_hit_marker_sound = ui.reference(
                'Visuals', 'Player ESP', 'Hit marker sound'
            )

            local function get_sound(is_headshot)
                local value = is_headshot
                    and ref.head_sound:get()
                    or ref.body_sound:get()

                if value == 'Off' then
                    return nil
                end

                return sounds[value]
                    or value .. '.wav'
            end

            local function on_shutdown()
                override.unset(ref_hit_marker_sound)
            end

            local function on_player_hurt(e)
                local me = entity.get_local_player()

                local userid = client.userid_to_entindex(e.userid)
                local attacker = client.userid_to_entindex(e.attacker)

                if me == userid or me ~= attacker then
                    return
                end

                local sound = get_sound(e.hitgroup == 1)

                if sound == nil then
                    return
                end

                playvol:invoke_callback(sound, ref.volume:get() / 100)
            end

            local function update_event_callbacks(value)
                if not value then
                    override.unset(ref_hit_marker_sound)
                end

                if value then
                    override.set(ref_hit_marker_sound, false)
                end

                utils.event_callback(
                    'shutdown',
                    on_shutdown,
                    value
                )

                utils.event_callback(
                    'player_hurt',
                    on_player_hurt,
                    value
                )
            end

            local callbacks do
                local function on_enabled(item)
                    update_event_callbacks(item:get())
                end

                ref.enabled:set_callback(
                    on_enabled, true
                )
            end
        end    end
end






















